INSERT INTO `dynasties` VALUES (1, '夏朝', '夏朝（约公元前2070年—约公元前1600年），是中国史书中记载的第一个奴隶制朝代。');
INSERT INTO `dynasties` VALUES (101, '商朝', '商朝（约公元前1600年—公元前1046年 ），是中国历史上的第二个朝代，也称殷商，是中国第一个有直接的同时期的文字记载的王朝。');
INSERT INTO `dynasties` VALUES (201, '西周', '西周（前1046～前771年），中国历史朝代。从周武王灭商到幽王亡国， 共传12王11代。');
INSERT INTO `dynasties` VALUES (301, '东周', '东周（公元前770年－公元前256年），西周覆灭后，诸侯拥立原先被废的太子姬宜臼为王，史称周平王，东迁洛邑，史称东周。');
INSERT INTO `dynasties` VALUES (401, '秦朝', '秦朝（前221年—前207年），是中国历史上第一个统一的封建王朝，秦朝结束了自战国以来诸侯分裂割据的局面，成为中国历史上第一个中央集权制国家。');
INSERT INTO `dynasties` VALUES (501, '汉朝', '汉朝（前202年－220年）是继秦朝之后的大一统王朝，分为西汉、东汉两个时期。其中西汉传十三帝，历二百一十年；东汉传十四帝，历一百九十五年。');
INSERT INTO `dynasties` VALUES (601, '三国', '三国（220年—280年），是中国历史时期。东汉末年中央集权制度崩溃，军阀四起，天下大乱。包括曹魏、蜀汉、东吴三个政权。');
INSERT INTO `dynasties` VALUES (701, '西晋', '西晋（265年 —316年），是中国历史上短暂的大一统王朝。传三世四帝 ，共51年。为了区别于五代时的后晋，史称西晋，又称为司马晋。');
INSERT INTO `dynasties` VALUES (801, '东晋', '东晋（317年—420年），是西晋皇族南迁后建立的王朝，是晋朝的继续。');
INSERT INTO `dynasties` VALUES (901, '十六国', '十六国（304年—439年 ），是中国历史上的一段大分裂时期。该时期自304年李雄和刘渊分别在汉地巴蜀建立成国（成汉）、在中原建立汉赵（前赵）时起，至439年北魏太武帝拓跋焘灭北凉，统一北方为止。');
INSERT INTO `dynasties` VALUES (1001, '北朝', '北朝（439年—581年），指中国南北朝时期存在于北方五个朝代的总称。北朝包括北魏、东魏、西魏、北齐和北周五朝');
INSERT INTO `dynasties` VALUES (1101, '南朝', '南朝承自东晋，从420年刘裕代晋算起，有南朝宋、南朝齐、南朝梁、南朝陈四朝，均以建康（今江苏南京）为都；北朝承自十六国，首个政权北魏于439年统一北方，推行改革，国势强盛，但于六镇之乱后衰落，在534年分裂为东魏、西魏。后来北齐代东魏，北周代西魏。');
INSERT INTO `dynasties` VALUES (1201, '隋朝', '隋朝（581年—618年），是中国历史上继南北朝之后的统一王朝，享国38年。');
INSERT INTO `dynasties` VALUES (1301, '唐朝', '唐朝（618年－907年），是中国历史上继隋朝后的大一统中原王朝，共历二十一帝，享国二百八十九年。');
INSERT INTO `dynasties` VALUES (1401, '五代十国', ' 五代十国（907 年 —979 年）是中国历史上的一段大分裂时期。这一称谓出自《新五代史》，是对五代（907 年 —960 年）的合称。');
INSERT INTO `dynasties` VALUES (1501, '宋朝', '宋朝（960年－1276年）是中国历史上承五代十国下启元朝的中原王朝，分北宋（960年－1127年）和南宋（1127年－1276年）两个阶段，共历十八帝，享国三百一十九年。');
INSERT INTO `dynasties` VALUES (1601, '辽朝', '辽朝（916—1125年），是中国历史上由契丹族建立的朝代，又称大契丹，民间或称大蕃。与北宋、西夏并立。共传九帝，经历二百零九年。');
INSERT INTO `dynasties` VALUES (1701, '西夏', '西夏（1038年—1227年），是中国历史上由党项人在中国西北部建立的朝代，自称“邦泥定国\\”或“大白高国\\”。因其在西北，故称之为西夏。前期和辽、北宋，后期与金朝、南宋并立。历经十帝，共189年。');
INSERT INTO `dynasties` VALUES (1801, '金朝', '金朝（1115年-1234年），是中国历史上由女真族建立的统治中国北方和东北地区的封建王朝，完颜阿骨打（完颜旻）所建。西与西夏、蒙古等接壤，南与南宋对峙。共传十帝，享国119年。');
INSERT INTO `dynasties` VALUES (1901, '元朝', '元朝（1271—1368年），是中国历史上的朝代。铁木真于1206年建国 ，1271年忽必烈定国号为大元 ，1279年灭南宋。是首次由少数民族建立的大一统王朝。自1206年铁木真建国始共163年，传15帝；自忽必烈改国号为大元起共98年，传11帝 ；自灭南宋起，统一时间共89年。');
INSERT INTO `dynasties` VALUES (2001, '明朝', '明朝（1368年―1644年），中国历史上的朝代，由明太祖朱元璋所建。初期建都南京，明成祖时期迁都北京。传十六帝，共计276年。');
INSERT INTO `dynasties` VALUES (2101, '清朝', '清朝（1616年或1644年—1911年），是中国历史上最后一个封建王朝，共传十二帝，初称后金。');
