INSERT INTO `persons` VALUES (1, '禹', '禹（生卒年不详），姒姓，夏后氏，名文命 ，上古时期夏后氏首领，夏朝开国君王 ，历史治水名人，史称大禹、帝禹、神禹。黄帝的玄孙、颛顼的后代，鲧的儿子。');
INSERT INTO `persons` VALUES (2, '姒启', '姒启（生卒年不详）， 也称夏启、帝启、夏后启、夏王启，阳翟（今河南省禹州市）人，禹和涂山氏族女子之子，夏朝的第二任君王。姒启一生四处征战，消除了华夏族内的反动势力，荒于音乐和饮食，最终病死');
INSERT INTO `persons` VALUES (3, '姒太康', '姒太康（生卒年不详），姒姓，夏后氏，阳翟（今河南省禹州市）人，启的长子，夏朝第三任君主。生活腐败，只顾游玩享乐不理朝政，后羿趁机夺权，驱逐了他，太康流亡至戈地。');
INSERT INTO `persons` VALUES (4, '姒中康', '中康（生卒年不详），一作仲康或仲卢，姒姓，夏后氏，阳翟（今河南省禹州市）人，夏启之子，太康之弟，夏朝第四任君主。后羿废黜太康之后，临朝八年，因诸侯不服，不得已立中康为王。');
INSERT INTO `persons` VALUES (5, '姒相', '相（生卒年不详），姒姓，夏后氏，斟鄩（今河南省洛阳市）人，夏朝第五代君主，中康之子，少康之父。中康死后，相即位。后羿称王后流亡，最终被寒浞所杀。');
INSERT INTO `persons` VALUES (6, '后裔', '后羿（约前1998年—前1940年），又称“夷羿”、“羿”，“后”是夏代君主尊号，夏代有穷氏首领。夏后仲康死后，其子相继位。不久，羿驱逐了相，自己当了君主，是为夏时代第六任君主。');
INSERT INTO `persons` VALUES (7, '寒浞', '寒浞（约前2013年-约前1933年），妘姓，名浞（zhuó）。夏朝时期的篡位君主。后羿执政8年，不修民事，寒浞趁机杀死后羿，夺取有穷氏大权。晚年骄奢淫逸，不修政事，最后死于姒相之子少康的复国之战中。');
INSERT INTO `persons` VALUES (8, '姒少康', '少康（生卒年不详），姒姓，有仍（今山东省金乡县）人，姒相的遗腹子，夏朝第六代君主。少康志在复国，攻灭寒浞，恢复了夏王朝的统治。');
INSERT INTO `persons` VALUES (9, '姒杼', '姒杼（生卒年不详），姒姓，夏后氏，帝丘（今河南省濮阳市）人，夏朝第七任君主。立下许多战功，发明了甲和矛，并大举征伐东夷部落，取得了胜利。');
INSERT INTO `persons` VALUES (10, '姒槐', '槐（生卒年不详），一作芬、祖武，老丘（今河南省开封市）人，杼的儿子，夏朝第八位君主。征服了许多部落，扩展了夏朝的势力。同时夏朝的社会经济都有所发展。');
INSERT INTO `persons` VALUES (11, '姒芒', '芒，别名帝芒、芒，夏朝第九任君主，槐的儿子。');
INSERT INTO `persons` VALUES (12, '姒泄', '泄，又名洩，姒姓，生卒年不详，夏朝第十位后');
INSERT INTO `persons` VALUES (13, '姒不降', '姒不降，姓姒，名不降，泄的儿子。老丘（今河南省开封市）人。不降统治期间，夏朝版图达到最大。');
INSERT INTO `persons` VALUES (14, '姒扃', '扃（生卒年不详），老丘（今河南省开封市）人，夏朝第十二任君主。泄的儿子，不降之弟。');
INSERT INTO `persons` VALUES (15, '姒廑', '廑（生卒年不详），老丘（今河南省开封市）人，夏朝第十三任君主。夏王扃之子。廑是夏朝的一位守成之君，此时的夏王朝国势强盛。');
INSERT INTO `persons` VALUES (16, '姒孔甲', '孔甲（生卒年不详），姒姓，名孔甲，老丘（今河南省开封市）人，不降的儿子，扃的侄子，廑的堂兄弟，夏朝第十四任君主。孔甲在位期间，喜好信奉鬼神，沉湎于歌舞美酒之中，是一位残暴昏君。');
INSERT INTO `persons` VALUES (17, '皋', '皋（生卒年不详），又作昊，或称简皋，夏朝第十五任君主，孔甲之子，在孔甲死后继承王位。');
INSERT INTO `persons` VALUES (18, '发', '发（生卒年不详），皋之子，是夏朝第十六任君主。其在位期间，施以仁政，爱护并重用贤臣良将，使夏朝更加繁荣。');
INSERT INTO `persons` VALUES (19, '桀', '桀，姒姓，夏后氏，名癸，帝发之子，桀是其谥号，故史称夏桀。伐有施氏，得美女妺喜，宠之。殚百姓之财，民不堪其苦。诸侯叛乱四起。商汤乘机伐夏，战于鸣条。他败走，被放逐于南巢而死，夏朝灭亡。');
INSERT INTO `persons` VALUES (101, '商汤', '商汤（生卒年不详）， 子姓，名履， 又称武汤、天乙、成汤，甲骨文称唐、大乙，又称高祖乙。 契的第十四代孙， 主癸之子。商王朝的建立者。');
INSERT INTO `persons` VALUES (102, '外丙', '外丙（生卒年不详）， 甲骨文作卜丙，名胜，外丙或卜丙是其庙号。成汤之子，商的旁系先王。《史记·殷本纪》说，成汤的太子太丁未及即位而去世，汤死之后，乃立太丁之弟外丙为帝，是以外丙为商的第二个国王。');
INSERT INTO `persons` VALUES (103, '仲壬', '仲壬（？～公元前1582年），本名子庸，汤第三子，在父兄相继去世后，于公元前1584年继位，伊尹摄政，公元前1582年去世，谥号懿，长兄太丁之子太甲继位。');
INSERT INTO `persons` VALUES (104, '太甲', '太甲（生卒年不详），子姓，名至。商汤嫡长孙，太丁之子，外丙和仲壬之侄，商朝第四位君主。太甲在位第十二年时去世。');
INSERT INTO `persons` VALUES (105, '沃丁', '沃丁（？-？），亦称羌丁，子姓，名绚，太甲之子，商朝第五任君主，沃丁在其父太甲死后继位。沃丁在位29年去世，死后由弟太庚即位。');
INSERT INTO `persons` VALUES (106, '太庚', '太庚（生卒年不详），又作大庚，误称小庚。姓子名辩，是商朝第六任君主。他是沃丁之弟，太甲之子。太庚在位期间，履行汤法，是商朝的一代明君。死后其子小甲继位。');
INSERT INTO `persons` VALUES (107, '小甲', '小甲（生卒年不详），名高，太庚之子，是中国商朝的第七位君王。小甲在位时，商代以亳为都，小甲死后弟雍己继立，商朝始衰。 殷墟卜辞将他列为旁系先王祭祀。');
INSERT INTO `persons` VALUES (108, '雍己', '雍己本名密，是太庚之子，小甲之弟、太戊之兄，小甲去世后他继承了商朝君主之位。雍己在位期间定都于亳，他昏庸无能，荒废政事，导致商朝衰落，各诸侯的势力日趋膨胀，以致很多诸侯故意不来朝贡。雍己死后其弟太戊即位');
INSERT INTO `persons` VALUES (109, '太戊', '太戊（？—前1401年） ，甲骨文作大太戊、天戊，子姓，名伷，商王太甲之孙，太庚之子，小甲和雍己的弟弟 ，商朝君主，在位七十五年 ，是商朝在位时间最长的一位君主。太戊死后葬于太戊陵（在今河南省内黄县亳城乡刘次范村东侧），其子中丁继位。');
INSERT INTO `persons` VALUES (110, '仲丁', '仲丁（生卒年不详），亦作中丁，子姓，名庄，商王太戊之子，商朝第十任君主。仲丁在位13年去世。仲丁死后，诸弟争夺王位，造成九世之乱，商朝一度中衰。');
INSERT INTO `persons` VALUES (111, '外壬', '外壬（？-？），在甲骨文中被称作卜壬，名发，商朝第十一任君主。商王太戊子，商王仲丁弟，仲丁死后继位。在位15年，病死，葬地不明。去世后由其弟河亶甲继位。');
INSERT INTO `persons` VALUES (112, '河亶甲', '河亶甲（？- ？），甲骨文作戋甲，吕氏春秋作整甲， 名整 ，是商王太戊之子，商王仲丁和外壬的弟弟，商朝第十二任君主。在其兄外壬死后继位。 河亶甲在位时，商朝再度衰落，无奈之下，他北上迁都于相（今河南安阳内黄），以缓解内外交困的局面。河亶甲在位9年病死，后葬于相。死后由其子祖乙继位。');
INSERT INTO `persons` VALUES (113, '祖乙', '祖乙，生卒年不详，亦称且乙，子姓，名滕（一作胜 ），商王仲丁之子 ，商朝第十三任君主。河亶甲死后，祖乙继任君主之位。 祖乙在位19年去世，庙号中宗 ，死后由其子祖辛继位。');
INSERT INTO `persons` VALUES (114, '祖辛', '祖辛（生卒年不详），甲骨文作且辛，商朝第十四任国王，姓子名旦，商王祖乙之子，祖乙去世后继位。在位16年，病死，葬于狄泉。死后由其弟沃甲即位，谥号商桓王。');
INSERT INTO `persons` VALUES (115, '沃甲', '沃甲，《世本》、《竹书纪年》作开甲，甲骨文作羌甲，子姓，名逾，商王祖辛之弟，商朝第十五任君主。沃甲的生平事迹不详，去世后由祖辛之子祖丁即位。');
INSERT INTO `persons` VALUES (116, '祖丁', '祖丁，在甲骨文中作且丁，姓子名新 ，商朝君主。祖辛之子，前任君主沃甲之侄，南庚堂兄，盘庚之父。（祖丁共在位九年（《今本竹书纪年》称他在位32年），他生平事迹不详，死后由沃甲之子南庚即位。');
INSERT INTO `persons` VALUES (117, '南庚', '南庚（生卒年不详），姓子名更，商朝第十七任君主。《史记·殷本纪》记载他是沃甲之子、祖丁堂弟 [1]，而殷墟卜辞说他为祖辛之子、祖丁之弟 [2]。祖丁死后继位。南庚在位时，商朝国运再度衰落，他将国都由庇（今山东省菏泽市郓城）迁至奄（今山东省济宁市曲阜县）。死后由祖丁之子阳甲继位。');
INSERT INTO `persons` VALUES (118, '阳甲', '阳甲在甲骨文中称象甲，是祖丁之子，南庚死后继位。阳甲在位期间定都于奄，曾西征丹山戎。此时的商朝内乱不止，诸侯不朝。阳甲已无法控制局面。阳甲在位7年（一说4年）后病死。');
INSERT INTO `persons` VALUES (119, '盘庚', '盘庚（生卒年不详），甲骨文作般庚，子姓，古本《竹书纪年》称他名旬 ，商王祖丁之子，阳甲之弟，商朝第十九位国王。 盘庚在其兄阳甲之后即位商朝国王。曾由奄（今山东曲阜）迁都至殷（今河南安阳小屯），并在迁都后重新施行商汤时期的政治制度，百姓得以安居乐业，商朝也因此再度兴盛。自迁殷以后，商朝政治基本稳定，都城不再迁徙。');
INSERT INTO `persons` VALUES (120, '小辛', '小辛是商朝第二十位国君，商王盘庚之弟，商王祖丁之子，姓子名颂。小辛在盘庚死后继位，相传在位21年。子颂继位后放弃了盘庚的治国之策，商朝国运又一次衰落。死后其弟小乙继位。');
INSERT INTO `persons` VALUES (121, '小乙', '小乙（？-？），姓子名敛，商朝第二十一位君主。他是前任君主小辛之弟，元年丁酉，王即位，居殷（河南安阳殷墟）。《外记》载其在位21年。死后由儿子武丁继位。');
INSERT INTO `persons` VALUES (122, '武丁', '武丁（?-前1192年），姓子，名昭，号武丁，又称殷武。商王小乙之子，商朝第二十二任君主。武丁在位期间从民间选拔贤才，兴利除弊，政治清明，百姓富庶，使商朝达到鼎盛，史称武丁中兴。公元前1192年，武丁去世，庙号高宗，由其子祖庚继位。');
INSERT INTO `persons` VALUES (123, '祖庚', '祖庚是商朝著名国王武丁次子，名曜 。祖庚有长兄祖己，祖己因受后母诬陷，被父亲武丁逐出京城，后含冤而死。三弟祖甲为后母所生，为表示不愿与兄长争夺王位，便暗暗地离宫出走，武丁病死，祖庚得以继位。祖庚在位7年，去世后由三弟祖甲继位。');
INSERT INTO `persons` VALUES (124, '祖甲', '祖甲（？- 公元前1152年），亦称且甲、帝甲，子姓，名载，商王武丁之子，商王祖庚之弟，商朝第二十四任君主，今本《竹书纪年》称他在位三十三年，曾征伐西戎，他在位早期尚能照顾民众，商朝中兴。祖甲死后由其子廪辛即位。');
INSERT INTO `persons` VALUES (125, '廪辛', '廪辛，《竹书纪年》作冯辛，姓子名先，是中国商朝的君主，前任商王祖甲之子。他死后由弟庚丁继位。');
INSERT INTO `persons` VALUES (126, '庚丁', '庚丁（生年不详一前1147）姓子名嚣，甲骨文作康且丁，又作康丁，《史记》、《竹书纪年》作庚丁 ，祖甲的儿子，廪辛的弟弟。廪辛死后继位。庚丁去世后由其子武乙继位。');
INSERT INTO `persons` VALUES (127, '武乙', '武乙（？―公元前1113年），子姓，名瞿，商王庚丁之子 ，商朝第二十七任君主 ，夏商周断代工程将其在位时间定为公元前1147年—公元前1113年在位 。公元前1147年，庚丁去世，武乙继位。公元前1113年，武乙去世，死后其子文丁继位。');
INSERT INTO `persons` VALUES (128, '文丁', '文丁（？—前1102年），《史记》作太丁 ，竹书纪年作大丁，子姓，名托，商王武乙之子，商朝第二十八任君主，在位11年。武乙去世后，文丁继位。武乙时，西方的周部落逐渐强大。文丁在位期间，周侯季历伐戎有功，文丁忌惮，先嘉其功而杀之，商周关系恶化。文丁死后，其子帝乙继位。');
INSERT INTO `persons` VALUES (129, '帝乙', '帝乙（？—公元前1076年），子姓，名羡 ，商王文丁（《史记》作太丁）之子 ，商朝第二十九任君主，夏商周断代工程将他在位时间定为公元前1101年—公元前1076年，共在位26年。 公元前1102年，文丁去世，帝乙继位。帝乙继位后，商朝国势已趋于没落。 帝乙在位末年，迁都于沬（mèi）（即朝歌，今河南省淇县）。公元前1076年，帝乙病逝，葬于殷。帝乙死后，其子帝辛（商纣王）继位。');
INSERT INTO `persons` VALUES (130, '帝辛', '帝辛（？—前1046年？），子姓，名受 （一作受德），商朝末代君主，世称纣（一说受之音转 ）、商纣王等。夏商周断代工程将其在位时间推定为三十年（前1075年—前1046年）。 帝辛是帝乙少子，继位后，在内大兴土木、加重赋敛、严格周祭制度、改变用人政策、推行严刑峻法，对外屡次发兵攻打东夷诸部落。其种种举措既在统治集团内部引发矛盾，也动摇了商王朝的统治基础。牧野之战，商军被周武王所率诸侯联军击败，帝辛身死，商朝灭亡。');
INSERT INTO `persons` VALUES (201, '姬昌', '姬昌（约前1152年—前1056年），姓姬，名昌 。商时为西伯，亦称伯昌 ，岐周（今陕西省岐山县）人。周太王之孙，季历之子 ，周武王之父，周朝奠基者。');
INSERT INTO `persons` VALUES (202, '姬发', '周武王姬发（？―约公元前1043年），姬姓，名发。周文王姬昌与太姒的嫡次子，岐周（今陕西岐山）人，西周王朝的开国君主。');
INSERT INTO `persons` VALUES (203, '姬诵', '姬诵（？～前1021年），姬姓，名诵，岐周（今陕西省岐山县）人。周朝第二位君王。周武王姬发与王后邑姜的儿子，太师姜子牙的外孙。');
INSERT INTO `persons` VALUES (204, '姬钊', '周康王姬钊（约公元前1036-前996年 ），姬姓，名钊，岐周（今陕西省岐山县）人。周朝第三任君主，周武王姬发的孙子，周成王姬诵的儿子 。');
INSERT INTO `persons` VALUES (205, '姬瑕', '周昭王姬瑕（？~前977年），岐周（今陕西省岐山县）人。周朝第四任君主，周康王姬钊的儿子。');
INSERT INTO `persons` VALUES (206, '姬满', '姬满，周穆王（？-约前922年），姬姓，名满。周昭王之子，西周第五位天子。是西周在位时间最长的周王，也是中国古代史籍记载的首位旅行家。');
INSERT INTO `persons` VALUES (207, '姬繄扈', '姬繄扈（？-约前900年），姬姓，名繄扈（yī hù，一作伊扈），周穆王姬满之子，西周第六位君主。谥共王，一作恭王，西周青铜器铭文多称他为龚王 。夏商周断代工程确定其在位时间为前922年至前900年。');
INSERT INTO `persons` VALUES (208, '姬囏', '姬囏，周懿王（约前937—前892年），姬姓，名囏（jiān），周共王姬繄扈（yī hù）之子，西周第七位君主。');
INSERT INTO `persons` VALUES (209, '姬辟方', '姬辟方，周孝王（？—前886年 ），姬姓，名辟方，周穆王姬满之子，周共王姬繄扈之弟，周懿王姬囏的叔父，西周第八位君主，在位时间前892年—前886年。');
INSERT INTO `persons` VALUES (210, '姬燮', '姬燮，周夷王（前885-878年），姬姓，名燮，西周第九代国王。姬燮在位时期，周王室处于衰落阶段，因此诸侯有的不来朝贡，而且互相攻伐。');
INSERT INTO `persons` VALUES (211, '姬胡', '姬胡（？-前828年），即周厉王。姬姓，名胡，金文作?。周夷王姬燮之子，中国西周王朝第十代王');
INSERT INTO `persons` VALUES (212, '姬静', '周宣王（？－前782年），姬姓，名静，一作靖，镐京（今陕西省西安市）人，周厉王之子，西周第十一代君主（前828年－前782年）');
INSERT INTO `persons` VALUES (213, '姬宫湦', '姬宫湦（前795年？―前771年），是指西周第十二任君主周幽王，姬姓，名宫湦（音shēng，一作宫生），周宣王姬静之子，母姜后，前781年―前771年在位。');
INSERT INTO `persons` VALUES (301, '姬宜臼', '周平王（前770―公元前720年），周幽王姬宫湦之子，东周第一任君主。因周幽王专宠褒姒而被废，公元前770年迁都洛邑，成为东周王。周平王时期，周室衰微，诸侯日益强大，于公元前720年去世。');
INSERT INTO `persons` VALUES (302, '姬林', '周桓王（前719—公元前697年），姬姓，名林，周平王姬宜臼之孙，太子姬泄之子，东周第二任君主。公元前720年即位，公元前697年去世，谥号桓王。');
INSERT INTO `persons` VALUES (303, '姬佗', '周庄王（前696—公元前682年），姬姓，名佗，周桓王姬林之子，东周第三任君主。公元前697年继位后，于公元前693年平定王子克之乱。公元前682年去世，谥号庄王，子姬胡齐继位，成为周釐王。');
INSERT INTO `persons` VALUES (304, '姬胡齐', '周釐王（前681—公元前677年），姬姓，名胡齐，周庄王姬佗长子，东周第四任君主。公元前682年继位，承认齐桓公的霸主地位，并于公元前678年册封晋武公为晋国国君。公元前677年去世。');
INSERT INTO `persons` VALUES (305, '姬阆', '周惠王（前676—前652年），姬姓，名阆，周釐王的儿子，中国东周时期第五代国王。在位期间占用卫国的园圃饲养野兽，引发不满；历经政变和复位，晚年宠爱惠后，欲立庶子为嗣，但未果。');
INSERT INTO `persons` VALUES (306, '姬郑', '周襄王（前651—前619年），姬姓，名郑，周惠王之子，东周第六任君主。在位时诸侯争霸日益激烈，齐桓公和晋文公的地位凌驾于周王及各诸侯国之上。');
INSERT INTO `persons` VALUES (307, '姬壬臣', '周顷王（前618—前613年），姬姓，名壬臣，周襄王之子，东周第七任国王。在位时王室财政拮据，需向鲁国求助来安葬其父周襄王，6年后去世，儿子周匡王继位。');
INSERT INTO `persons` VALUES (308, '姬班', '周匡王（前612—前607年），姬姓，名班，周顷王之子，东周第八位君王。在位共6年，于前607年10月病死，弟弟姬瑜继位。');
INSERT INTO `persons` VALUES (309, '姬瑜', '周定王（前606—前586年），姬姓，名瑜，周顷王之子，周匡王之弟，东周第九位君王。在位21年，期间中央权力持续削弱，社会动荡，周定王崩后，其子周简王姬夷即位。');
INSERT INTO `persons` VALUES (310, '姬夷', '周简王（前585—前572年），姬姓，名夷，周定王之子，东周第十位君王。在位14年，周天子权威荡然无存，公元前572年病死，其子姬泄心即位。');
INSERT INTO `persons` VALUES (311, '姬泄心', '周灵王（前571—前545年），姬姓，名泄心，东周第十一任君主，周简王之子，在位27年。育有二子：长太子姬晋、次子姬贵。周简王去世后，灵王继位，终因病去世，太子姬晋的同母弟姬贵继位。');
INSERT INTO `persons` VALUES (312, '姬贵', '周景王（前544—前520年），姬姓，名贵，东周第十二任君主。在位期间财政困难，曾需向各国乞讨器物。因宠爱庶子王子朝而导致王子朝之乱，公元前520年去世。');
INSERT INTO `persons` VALUES (313, '姬猛', '周悼王（前520年），姬姓，名猛，周景王次子，东周第十三任君主。因王子朝之乱未能正式即位，去世后谥号悼王。');
INSERT INTO `persons` VALUES (314, '姬匄', '周敬王（前519—前476年），姬姓，名匄，东周第十四任君主。因王子朝之乱被拥立，在位期间迁都、与王子朝冲突，最终于前476年去世。');
INSERT INTO `persons` VALUES (315, '姬仁', '周元王（前475—前469年），姬姓，名仁，东周第十五任君主，周敬王之子，在位8年。');
INSERT INTO `persons` VALUES (316, '姬介', '周贞王（前468—前441年），姬姓，名介，东周第十六任君主，周元王之子，在位28年，谥号贞定王。公元前441年春，姬介病死。');
INSERT INTO `persons` VALUES (317, '姬去疾', '周哀王（前441年），姬姓，名去疾，周贞定王之子。于前441年即位，但在即位后三个月便被弟弟姬叔袭杀，葬处不明，死后谥号为哀王。');
INSERT INTO `persons` VALUES (318, '姬叔', '周思王（前441年），姬姓，名叔，周贞定王之子，周哀王之弟。于公元前441年三月袭杀弟弟周哀王即位，在位仅五个月，八月被弟弟姬嵬杀死。');
INSERT INTO `persons` VALUES (319, '姬嵬', '周考王（前440—前426年），姬姓，名嵬，周贞定王之子，周哀王、周思王之弟。于公元前441年杀害其兄周思王自立，在位15年，公元前426年去世，谥号考王。');
INSERT INTO `persons` VALUES (320, '姬午', '周威烈王（前425—前402年），姬姓，名午，周考王之子，东周第20代君主。位24年，病死。公元前403年，进行封诸侯的举措，此为“三家分晋”，标志着春秋时代的结束与战国时代的来临。');
INSERT INTO `persons` VALUES (321, '姬骄', '周安王（前401—前376年），姬姓，名骄，华夏族，周威烈王之子，东周第三十三位国君，在位26年，病死，葬处不明。在位期间封齐国大夫田和为齐侯，史称“田氏代齐”。');
INSERT INTO `persons` VALUES (322, '姬喜', '周烈王（前375—前369年），姬姓，名喜，周安王之子，东周第二十二任君主，在位期间谥号为烈王。于公元前376年至前369年在位，公元前369年去世。');
INSERT INTO `persons` VALUES (323, '姬扁', '周显王（前368—前321年），姬姓，名扁，亦称周显圣王或周显声王，东周君主，在位48年，周烈王之弟。公元前369年即位。');
INSERT INTO `persons` VALUES (324, '姬定', '周慎靓王（前320—前315年），姬姓，名定，亦名顺，东周君主，在位6年，为周显王之子。周王时期，战国七雄为了壮大势力而各自寻找盟友，公元前315年病死，谥号为慎靓王。');
INSERT INTO `persons` VALUES (325, '姬延', '周赧王（前314—前256年），姬姓，名延，洛邑人，周慎靓王之子，东周第二十五位国王，也是东周最后一位君主。在位期间，周王室已十分衰弱，楚国曾以天子名义号令各国攻秦。');
INSERT INTO `persons` VALUES (326, '姜太公', '姜太公（？－前1015年或前1036年），姜姓，吕氏，名尚或望，字子牙（或单呼“牙”），后世称姜子牙、齐太公、师尚父、太公望、吕望、吕尚、姜尚等。中国商朝末年军事家、政治家、韬略家、思想家，西周开国元勋。');
INSERT INTO `persons` VALUES (327, '齐庄公', '周宣王三十三年（前794），齐庄公吕购即位。齐庄公历经西周末年和春秋初期两个时期，在位六十四年，是齐国在位时间最长的君主。齐庄公励精图治，使齐人安居乐业，算得上齐国历史上的中兴之主。');
INSERT INTO `persons` VALUES (328, '齐僖公', '齐僖公（？―公元前698年），一作齐釐公，姜姓，吕氏，名禄甫，齐前庄公之子，春秋时期齐国国君，是春秋三小霸之一。');
INSERT INTO `persons` VALUES (329, '齐恒公', '齐桓公（？～前643年），姜姓，吕氏，名小白。齐国第十六位国君，春秋五霸之首，姜太公吕尚的第十二代孙，齐僖公第三子，母为卫姬。');
INSERT INTO `persons` VALUES (330, '齐太公', '齐太公田和（？―前385年），妫姓，田氏，名和，称为子禾。前391年，田和自立为齐君。放逐齐康公于海岛，使食一城，以奉姜姓之祀。前379年，齐康公死，田氏并其食邑，吕尚至此绝祀。');
INSERT INTO `persons` VALUES (331, '齐威王', '齐威王（？—前320年），妫姓，田氏，名因齐 ，一名婴齐，齐桓公田午之子，战国时齐国国君。');
INSERT INTO `persons` VALUES (332, '齐王建', '齐王建（约公元前280年─公元前221年），亦称齐废王、齐共王，妫姓，田氏，名建，齐襄王之子，战国时期齐国最后一位国君。');
INSERT INTO `persons` VALUES (333, '唐叔虞', '唐叔虞（生卒年不详），姬姓，名虞，字子于，岐周（今陕西岐山）人。西周时期晋国始祖、三晋文化创始人。在封地唐国，史称唐叔虞。');
INSERT INTO `persons` VALUES (334, '晋武公', '晋武公（公元前754年—公元前677年），又称曲沃武公，姬姓，名“称”，晋穆侯曾孙，曲沃桓叔之孙，曲沃庄伯之子，春秋时期晋国国君。');
INSERT INTO `persons` VALUES (335, '晋献公', '晋献公，姬姓，名诡诸，曲沃（今山西省闻喜县）人。春秋时期晋国第19任君主，晋武公之子，在位26年。');
INSERT INTO `persons` VALUES (336, '晋文公', '晋文公姬重耳（前697年或前671年－前628年），姬姓，晋氏，名重耳，是中国春秋时期晋国的第二十二任国君（前636年－前628年在位），晋献公之子');
INSERT INTO `persons` VALUES (337, '晋静公', '晋静公（？—公元前349年？），又称晋靖公、晋后悼公。姬姓，名俱酒，是东周时晋国的最后一位君主，晋孝公之子。');
INSERT INTO `persons` VALUES (338, '秦襄公', '秦襄公（？—前766年），嬴姓，名失传。庄公次子。春秋初秦国国君。');
INSERT INTO `persons` VALUES (339, '秦宣公', '秦宣公（？—公元前664年），嬴姓，秦德公长子，秦成公和秦穆公的长兄，春秋时期秦国第七位国君。');
INSERT INTO `persons` VALUES (340, '秦孝公', '秦孝公（前381年～前338年），嬴姓，名渠梁，亦称秦平王。秦献公之子，秦惠文王之父。战国时期的秦国第二十五位国君。');
INSERT INTO `persons` VALUES (341, '秦王政', '秦始皇嬴政（前259年—前210年），嬴姓，赵氏（一说秦氏），名政。中国古代杰出的政治家、战略家、改革家，中国历史上第一个专制主义中央集权国家——秦朝的建立者，中国第一位称皇帝的君主。');
INSERT INTO `persons` VALUES (342, '熊绎', '熊绎（生卒年不详），芈姓，熊氏，名绎，鬻熊曾孙，西周诸侯国楚国始封君。周成王时，在周都镐京的熊绎，受周天子分封南蛮之地，建立楚国。');
INSERT INTO `persons` VALUES (343, '楚庄王', '楚庄王（？～前591年），又称荆庄王，芈姓，熊氏，名旅（一作侣、吕），春秋时期楚国国君，春秋五霸之一。楚穆王之子。');
INSERT INTO `persons` VALUES (344, '楚悼王', '楚悼王（？- 前381年 ），芈姓，熊氏，名疑（一作类），楚声王之子，战国时期楚国国君。');
INSERT INTO `persons` VALUES (345, '楚王负刍', '楚王负刍，芈姓，熊氏，名负刍，楚考烈王之子，战国时期楚国末代国君。公元前228年，负刍的门客杀死楚哀王，负刍自立为楚王。公元前223年，秦军攻入楚都，楚王负刍被俘，楚国灭亡。');
INSERT INTO `persons` VALUES (346, '魏文侯', '魏文侯（？～前396年），姬姓，魏氏，名斯（一名都），安邑（今山西省夏县）人。魏桓子之孙，魏武侯之父。战国时期魏国开国君主。');
INSERT INTO `persons` VALUES (347, '魏惠王', '魏惠王（前400年 - 前319年），即梁惠王，姬姓魏氏，名罃（通“?”，亦作“婴” “莹”）。战国时魏国第三任国君。魏武侯之子。');
INSERT INTO `persons` VALUES (348, ' 魏王假 ', ' 魏王假（生卒年不详），战国魏国末代君主。公元前 225 年，秦军引河灌大梁，城破后其投降，魏国灭亡。');
INSERT INTO `persons` VALUES (349, '韩景候', '韩景侯（？—公元前400年），姬姓，韩氏，名虔，晋卿韩武子之子，战国时期韩国国君。公元前 403 年，获周威烈王册封，正式建立韩国。');
INSERT INTO `persons` VALUES (350, '韩哀侯', '韩哀侯（？－前374年），韩国阳翟（今河南省禹州市）人，战国时期韩国第4任君主。公元前 375 年，出兵灭亡郑国，迁都新郑，韩国实力大增。');
INSERT INTO `persons` VALUES (351, '韩昭侯 ', '韩武（？－前333年），姬姓韩氏，韩懿侯之子，战国时期韩国第6位国君。任用申不害变法，推行以 “术” 治国，韩国国力提升。');
INSERT INTO `persons` VALUES (352, '韩王安', '韩王安（？-前226年），也称韩废王，姬姓韩氏，名安。公元前 230 年，秦国攻韩，韩王安投降，韩国灭亡。');
INSERT INTO `persons` VALUES (353, '赵烈侯', '赵烈侯（？—公元前400年），嬴姓，赵氏，名籍，赵献子（后追封为赵献侯）之子，战国时期晋国赵氏封君、赵国开国君主。');
INSERT INTO `persons` VALUES (354, '赵武灵王', '赵武灵王（？－前295年），嬴姓，赵氏，名雍，赵国邯郸（今河北省邯郸市）人。先秦时代杰出的政治家、军事家、改革家，战国时期赵国第六代君主。');
INSERT INTO `persons` VALUES (355, '赵孝成王', '赵孝成王（？～前245年），嬴姓，赵氏，名丹，东周战国时期赵国第八代君主。在位期间，赵国经历长平之战惨败，国力由盛转衰。');
INSERT INTO `persons` VALUES (356, '赵王迁', '赵王迁（？—公元前222年之前），亦称赵幽缪王，嬴姓，赵氏，名迁。战国时期赵国最后一位国君。公元前 228 年，秦军攻破邯郸，赵王迁被俘，赵国灭亡。');
INSERT INTO `persons` VALUES (357, '燕侯克', '姬奭（生卒年不详），又称召公、召伯、召康公。姬奭佐武王灭商后，封于燕。');
INSERT INTO `persons` VALUES (358, '燕昭王', '燕昭王（？ - 公元前279年），姬姓燕氏，名职，燕国蓟城（今北京市）人，战国时燕国第39任国君。在位期间广纳贤才，振兴燕国，组织五国伐齐，使燕国达到鼎盛。');
INSERT INTO `persons` VALUES (359, '燕王喜', '燕王喜（不详），姬姓燕氏，名喜，燕国蓟城（今北京市）人，战国时燕国第43任国君。遣使荆轲刺秦失败，最终被秦国所灭。');
INSERT INTO `persons` VALUES (401, '嬴政', '秦始皇嬴政（前259年—前210年），嬴姓，赵氏（一说秦氏），名政（一说正） ，也有祖龙、吕政等别称。中国古代杰出的政治家、战略家、改革家，中国历史上第一个专制主义中央集权国家——秦朝的建立者，中国第一位称皇帝的君主。前210年，嬴政驾崩于沙丘平台，享年五十岁，葬于骊山秦始皇陵。死后由胡亥继位，翌年就爆发了埋葬秦朝的秦末农民战争。');
INSERT INTO `persons` VALUES (402, '胡亥', '胡亥（前230年/前221年—前207年），即秦二世，嬴姓，赵氏，名胡亥，秦始皇第十八子，公子扶苏之弟。秦朝第二位皇帝。秦始皇三十七年（前210年），始皇帝病死。胡亥在赵高和丞相李斯的扶植下，得立为太子继而承袭帝位。即位后胡亥实行残暴的统治，群臣人人自危。二世三年（前207年）七月，刘邦带领的起义军攻下武关。赵高与其婿咸阳令阎乐合谋，诈诏发兵包围望夷宫，胡亥被迫自杀。');
INSERT INTO `persons` VALUES (501, '刘邦', '汉高帝刘邦（前256年 /前247年－前195年6月1日），字季，沛丰邑中阳里人（今江苏省徐州市丰县），中国历史上杰出的政治家、战略家，汉朝开国皇帝（前202年2月28日－前195年6月1日 在位）');
INSERT INTO `persons` VALUES (502, '刘盈', '汉惠帝刘盈（前211年—前188年9月24日），汉高祖刘邦与皇后吕雉的嫡长子， 西汉第二位皇帝（前195年6月20日 —前188年9月24日 在位 ）。');
INSERT INTO `persons` VALUES (503, '刘恭', '汉前少帝刘恭（？—前184年6月15日），名不详，汉惠帝刘盈长子，西汉第三位皇帝，汉惠帝七年（前188年）至汉高后四年（前184年）在位。');
INSERT INTO `persons` VALUES (504, '刘弘', '西汉后少帝刘弘（?―前180年11月14日），原名刘山，曾用名刘义，汉惠帝刘盈之子，西汉第四位皇帝，前184年6月15日－前180年11月14日在位');
INSERT INTO `persons` VALUES (505, '刘恒', '汉文帝刘恒（前203年-前157年） ，西汉开国皇帝刘邦第四子，母为薄姬。 汉朝第五个皇帝。');
INSERT INTO `persons` VALUES (506, '刘启', '汉景帝刘启（前188年—前141年3月7日），西汉第六位皇帝（前157年7月12日—前141年3月7日在位）。其父为汉文帝刘恒，其母为孝文窦皇后窦氏（即窦太后）。');
INSERT INTO `persons` VALUES (507, '刘彻', '汉武帝刘彻（前156年—前87年），西汉第七位皇帝（前141年—前87年在位），中国历史上杰出的政治家、军事家、战略家、文学家。 汉景帝刘启与王皇后之子。');
INSERT INTO `persons` VALUES (508, '刘弗陵', '汉昭帝刘弗陵（前94年—前74年），西汉第八位皇帝（公元前87年—前74年在位），汉武帝刘彻少子，母为钩弋夫人赵氏。');
INSERT INTO `persons` VALUES (509, '刘贺', '刘贺（前92年-前59年）， 即海昏侯，又称西汉废帝，出生于昌邑国昌邑县（今山东省菏泽市巨野县） 。汉武帝刘彻之孙，昌邑哀王刘髆之子， 西汉第九位皇帝，也是西汉历史上在位时间最短的皇帝。');
INSERT INTO `persons` VALUES (510, '刘询', '汉宣帝刘询（前91年－前48年1月10日），原名刘病已，字次卿，西汉第十位皇帝（前74年9月8日－前48年1月10日在位），汉武帝刘彻曾孙，戾太子刘据之孙，史皇孙刘进之子。');
INSERT INTO `persons` VALUES (511, '刘奭', '汉元帝刘奭（前74年—前33年7月8日 ），汉宣帝刘询与嫡妻许平君所生之子，西汉第十一位皇帝（前48年1月29日 —前33年7月8日 在位）。');
INSERT INTO `persons` VALUES (512, '刘骜', '汉成帝刘骜 （前51年～前7年4月15日），字太孙，汉元帝刘奭与王莽姑王政君之子，中国西汉第十二位皇帝（前33年8月4日 ～前7年4月15日 在位）。');
INSERT INTO `persons` VALUES (513, '刘欣', '汉哀帝刘欣（前25年—前1年8月15日），兖州定陶（今山东菏泽市）人。西汉第十三位皇帝。汉元帝刘奭之孙，定陶恭王刘康之子。');
INSERT INTO `persons` VALUES (514, '刘衎', '汉平帝刘衎（前9年－6年2月3日），原名刘箕子，汉元帝刘奭之孙，中山孝王刘兴之子，母卫姬 ，西汉第十四位皇帝。');
INSERT INTO `persons` VALUES (515, '王莽', '王莽（前45年—23年），字巨君，魏郡元城（今河北邯郸）人，新朝唯一皇帝，改革家，政治家， 汉元帝皇后王政君之侄， 西汉新都侯王曼之子。');
INSERT INTO `persons` VALUES (516, '刘玄', '更始帝刘玄（？～25年），字圣公，南阳郡蔡阳县（今湖北省枣阳市）人。汉朝宗室后代，汉景帝刘启之子长沙定王刘发的后代，汉光武帝刘秀的族兄');
INSERT INTO `persons` VALUES (517, '刘秀', '汉武帝刘秀（前5年1月15日—57年3月29日），字文叔，南阳郡蔡阳县人（今湖北枣阳市，一说河南南阳市），汉高祖刘邦九世孙，东汉开国皇帝（25年8月5日—57年3月29日在位），中国历史上杰出的政治家、军事家。');
INSERT INTO `persons` VALUES (518, '刘庄', '汉明帝刘庄（28年6月15日—75年9月5日），字子丽，东汉王朝第二位皇帝（57年3月29日 —75年9月5日 在位），光武帝刘秀第四子，母为光烈皇后阴丽华。');
INSERT INTO `persons` VALUES (519, '刘炟', '汉章帝刘炟（56年－88年4月9日），东汉第三位皇帝（75年－88年在位），光武帝刘秀的孙子，汉明帝刘庄第五子，母为贾贵人。');
INSERT INTO `persons` VALUES (520, '刘肇', '汉和帝刘肇（79年－106年2月13日），一作刘肈，中国东汉第四位皇帝（88年4月9日 －106年2月13日在位），汉章帝刘炟第四子。');
INSERT INTO `persons` VALUES (521, '刘隆', '汉殇帝刘隆（105年11月5日—106年9月21日），东汉第五位皇帝，汉和帝刘肇少子。');
INSERT INTO `persons` VALUES (522, '刘祜', '汉安帝刘祜（94年－125年4月30日），东汉第六位皇帝（106年－125年在位），汉章帝刘炟之孙，清河孝王刘庆之子，母为左小娥。');
INSERT INTO `persons` VALUES (523, '刘懿', '刘懿（？- 125年），一名犊，汉章帝刘炟之孙，济北惠王刘寿之子，汉安帝刘祜堂弟，东汉第七任皇帝，125年5月18日―125年12月10日在位。');
INSERT INTO `persons` VALUES (524, '刘保', '汉顺帝刘保（115年－144年9月20日），东汉第八位皇帝（125年12月16日 －144年9月20日在位），汉安帝长子，恭愍皇后李氏所生，中国古代杰出的政治家、改革家，科举制的奠基人。');
INSERT INTO `persons` VALUES (525, '刘炳', '汉冲帝刘炳（143年－145年2月15日），汉顺帝刘保之子，母虞贵人，东汉第九位皇帝。');
INSERT INTO `persons` VALUES (526, '刘缵', '汉质帝刘缵（138年—146年7月26日），又名刘续，东汉第十位皇帝（145年—146年在位），汉章帝刘炟玄孙，渤海孝王刘鸿之子。');
INSERT INTO `persons` VALUES (527, '刘志', '汉桓帝刘志（132年－168年1月25日），汉章帝刘炟曾孙，河间孝王刘开之孙，蠡吾侯刘翼之子，东汉第十一位皇帝。');
INSERT INTO `persons` VALUES (528, '刘宏', '刘宏（公元156年—189年5月13日）， 世称汉灵帝。汉章帝刘炟之玄孙，中国东汉第12位皇帝（公元168年2月17日 —189年5月13日 在位）。');
INSERT INTO `persons` VALUES (529, '刘辩', '刘辩（173年10月14日一说176年 -190年3月6日 ），汉灵帝刘宏与何皇后的嫡长子，中国东汉皇帝，史称汉废帝、汉少帝。');
INSERT INTO `persons` VALUES (530, '刘协', '汉献帝刘协（181年4月2日 —234年4月21日），字伯和，东汉末代皇帝。汉灵帝刘宏次子，汉少帝刘辩异母弟，母为灵怀皇后王荣。');
INSERT INTO `persons` VALUES (601, '汉昭烈帝', ' 刘备（161 年 - 223 年），蜀汉开国皇帝。以 “兴复汉室” 为目标，经赤壁之战、夺取益州等，于公元 221 年称帝，建立蜀汉政权。');
INSERT INTO `persons` VALUES (602, '汉怀帝', ' 刘禅（207 年 - 271 年），蜀汉末代皇帝。在位前期有诸葛亮辅佐，后期朝政逐渐腐败，公元 263 年，魏军攻蜀，刘禅投降，蜀汉灭亡。');
INSERT INTO `persons` VALUES (603, '吴大帝 ', '孙权（182 年 - 252 年），三国时期孙吴开国皇帝。继承父兄基业，经赤壁之战、夷陵之战等，巩固江东统治，于 229 年称帝。');
INSERT INTO `persons` VALUES (604, '会稽王', '孙亮（243 年 - 260 年），孙权幼子，10 岁继位。在位时权臣争权，后被废。');
INSERT INTO `persons` VALUES (605, '吴景帝', '孙休（235 年 - 264 年），孙权第六子，被孙綝拥立为帝。在位时诛杀孙綝，使东吴进入短暂恢复期。');
INSERT INTO `persons` VALUES (606, ' 吴末帝 ', '孙皓（242 年 - 284 年），孙权之孙，孙和之子。在位期间专横残暴，奢侈荒淫，280 年向晋投降，吴亡。');
INSERT INTO `persons` VALUES (607, ' 魏文帝 ', '曹丕（187 年 - 226 年），曹魏开国皇帝。废汉称帝，建立曹魏政权，推行九品中正制，加强中央集权。');
INSERT INTO `persons` VALUES (608, ' 魏明帝 ', '曹叡（204 年 - 239 年），曹魏第二位皇帝。在位期间，指挥曹真、司马懿等人成功防御吴、蜀的多次攻伐，后大兴土木，滥用民力。');
INSERT INTO `persons` VALUES (609, ' 魏齐王 ', '曹芳（232 年 - 274 年），曹魏第三位皇帝。在位前期由曹爽、司马懿辅政，后司马氏专权，曹芳被废。');
INSERT INTO `persons` VALUES (701, '司马炎', '晋武帝司马炎（236年—290年5月16日），字安世，河内郡温县（今河南省温县）人。中国西晋开国皇帝（266年2月8日—290年5月16日在位)，晋宣帝司马懿之孙，晋文帝司马昭嫡长子 ，母为文明皇后王元姬。司马炎在父祖开创的政治基础上，建立晋朝，渡江灭吴，完成了三国统一的历史伟业。太熙元年(290年)，司马炎在洛阳含章殿病逝，时年五十五岁，谥号武皇帝，庙号世祖，安葬于峻阳陵。');
INSERT INTO `persons` VALUES (702, '司马衷', '司马衷（259年－307年1月8日），字正度，河内郡温县（今河南省温县）人。西晋第二位皇帝（290年5月16日 —307年1月8日 在位），晋武帝司马炎嫡次子，母为武元皇后杨艳。光熙元年十一月庚午日（307年1月8日），去世，时年四十八岁，谥号为惠，安葬于太阳陵。');
INSERT INTO `persons` VALUES (703, '司马炽', '司马炽（284年—313年3月14日），字丰度，河内温县（今河南省温县）人。西晋第三位皇帝（307年—311年在位），晋武帝司马炎第二十五子，晋惠帝司马衷异母弟，母为王媛姬。建兴元年（313年3月14日），为刘聪所毒杀，时年三十岁。');
INSERT INTO `persons` VALUES (704, '司马邺', '晋愍帝司马邺（300年～318年2月7日），一作司马业，字彦旗，河内郡温县（今河南省温县）人。西晋末代皇帝。武帝司马炎之孙，吴敬王司马晏之子，怀帝司马炽之侄。建兴五年十二月戊戌日（318年2月7日），司马邺在平阳被汉赵皇帝刘聪杀害，年仅十八岁，葬处不明，谥号愍皇帝。');
INSERT INTO `persons` VALUES (801, '司马睿', '晋元帝司马睿（276年－323年1月3日），字景文，河内郡温县（今河南省温县）人。中国东晋开国皇帝，晋宣帝司马懿曾孙，琅邪恭王司马觐之子。');
INSERT INTO `persons` VALUES (802, '司马绍', '司马绍 (299年～325年)，字道畿，河内郡温县?(今河南省温县) 人，生于琅琊国?(今山东省临沂市)。东晋第二位皇帝，晋元帝司马睿的长子，晋简文帝司马昱异母兄，母为宫人荀氏。');
INSERT INTO `persons` VALUES (803, '司马衍', '司马衍（321年－342年7月26日），字世根，东晋第三位皇帝。晋明帝司马绍长子，晋康帝司马岳同母兄，母为明穆皇后庾文君。');
INSERT INTO `persons` VALUES (804, '司马岳', '司马岳（322年－344年11月17日），字世同，生于建康县（今江苏省南京市）。东晋第四位皇帝（342年7月27日－344年11月17日），晋明帝司马绍嫡次子，晋成帝司马衍同母弟，母为明穆皇后庾文君。');
INSERT INTO `persons` VALUES (805, '司马聃', '晋穆帝司马聃（343年－361年7月10日），字彭子，生于建康县（今江苏省南京市），东晋第五位皇帝（344年11月18日－361年7月10日）。晋康帝司马岳与康献皇后褚蒜子的长子。');
INSERT INTO `persons` VALUES (806, '司马丕', '司马丕（341年－365年3月30日），字千龄，河内温县（今河南省温县）人。东晋第六位皇帝（361年7月13日?—365年3月30日在位），晋成帝司马衍长子，母为周贵人。');
INSERT INTO `persons` VALUES (807, '司马奕', '司马奕（342年－386年11月23日?），字延龄，河内郡温县（今河南省温县）人，生于建康县（今江苏省南京市）。东晋第七位皇帝（365年3月31日－372年1月6日在位?），晋成帝司马衍的次子，晋哀帝司马丕同母弟，母为周贵人，东晋唯一一位在位期间被废的皇帝。');
INSERT INTO `persons` VALUES (808, '司马昱', '司马昱（320年－372年9月12日），字道万，祖籍河内郡温县（今河南省温县）。东晋第八位皇帝（372年1月6日－9月12日在位），晋元帝司马睿幼子，晋明帝司马绍异母弟，母为简文宣太后郑阿春。');
INSERT INTO `persons` VALUES (809, '司马曜', '晋孝武帝司马曜（362年—396年11月6日），字昌明，东晋第九任皇帝（372年9月12日—396年11月6日在位）。晋简文帝司马昱第六子，母为李陵容。');
INSERT INTO `persons` VALUES (810, '司马德宗', '司马德宗（382年~419年1月28日），字德宗，晋孝武帝司马曜长子，晋恭帝司马德文同母兄。晋朝第十四位，东晋的第十位皇帝。司马德宗即位后，内乱频发，国势日衰，419年被刘裕杀死。时年37岁。');
INSERT INTO `persons` VALUES (811, '司马德文', '司马德文（386年～421年九月），字德文，祖籍河内郡温县（今河南省温县）人。东晋末代皇帝，东晋孝武帝司马曜次子，东晋安帝司马德宗之弟，母为淑媛陈归女。');
INSERT INTO `persons` VALUES (901, ' 张轨 ', ' 张轨（255 年 - 314 年），前凉政权奠基者。西晋末年出任凉州刺史，在河西地区站稳脚跟，为前凉发展奠定基础。');
INSERT INTO `persons` VALUES (902, ' 张重华 ', ' 张重华（327 年 - 353 年），前凉文王张骏之子。在位时重用贤臣谢艾，多次成功抵御后赵进攻，前凉国势达到极盛。');
INSERT INTO `persons` VALUES (903, ' 张天锡 ', ' 张天锡（？ - 398 年），前凉末代君王。前秦建元十二年（376 年），苻坚大军压境，张天锡投降，前凉灭亡。');
INSERT INTO `persons` VALUES (904, ' 成武帝李雄 ', ' 成武帝李雄（274 年 - 334 年），成汉开国皇帝。建立大成政权，轻徭薄赋，使蜀地安定。');
INSERT INTO `persons` VALUES (905, ' 归义侯李势 ', ' 归义侯李势（？ - 361 年），成汉末代皇帝。荒淫无道，347 年成汉被东晋桓温所灭。');
INSERT INTO `persons` VALUES (906, '刘渊', '刘渊（？ - 310 年），前赵开国皇帝，建立汉赵政权，为前赵发展奠定基础。');
INSERT INTO `persons` VALUES (907, '刘曜,', '刘曜（？～329年），字永明，新兴郡（今山西省忻州市）人，匈奴族。汉赵末代皇帝、军事家。光文帝刘渊堂侄，宣成帝刘绿之子。');
INSERT INTO `persons` VALUES (908, '石勒', '石勒（274 年 - 333 年），羯族，后赵开国君主。以卓越军事才能统一北方大部，重视农业与文化，奠定后赵基业。');
INSERT INTO `persons` VALUES (909, '石虎', '石虎（295年～349年），字季龙，上党郡武乡县（今山西省榆社县）人，羯族。后赵第三位君主、军事家。');
INSERT INTO `persons` VALUES (910, '石祗', '石祗（？ ～351年），上党郡武乡县（今山西省榆社县）人，后赵武帝石虎之子，后赵末代皇帝');
INSERT INTO `persons` VALUES (911, '段业', '段业（？～401年），京兆郡（今陕西省西安市）人，汉族，北凉开国国君。公元399年，段业自称凉王，改元天玺。');
INSERT INTO `persons` VALUES (912, '沮渠安周', '沮渠安周（？～460年），复姓沮渠，张掖临松（今甘肃省张掖市）人，匈奴族。十六国时期高昌北凉末代国君，北凉武宣王沮渠蒙逊的儿子，北凉哀王沮渠牧犍、河西王沮渠无讳的弟弟。');
INSERT INTO `persons` VALUES (913, '苻健', '苻健（317年～355年），初名蒲罴，字建业、世建，略阳郡临渭县（今甘肃省秦安县）人，氐族。前秦开国皇帝、政治家、军事家。');
INSERT INTO `persons` VALUES (914, '苻崇', '苻崇（？～394年），祖籍略阳郡临渭县（今甘肃省秦安县）人，氐族。前秦末代皇帝。');
INSERT INTO `persons` VALUES (915, '慕容垂', '慕容垂（约326年～396年），鲜卑名阿六敦，原名霸，字道业，后改名垂，字道明。昌黎郡棘城县（今辽宁省义县）人，鲜卑族。后燕开国皇帝、军事家。');
INSERT INTO `persons` VALUES (916, '慕容熙', '慕容熙（385年～407年），字道文，一字长生，祖籍昌黎郡大棘城（今辽宁省义县）人，出生于常山郡（今河北省石家庄市），后燕末代皇帝。');
INSERT INTO `persons` VALUES (917, '姚苌', '姚苌（330年～393年），字景茂，祖籍南安郡赤亭县（今甘肃省陇西县）人，羌族。后秦开国皇帝、军事家。');
INSERT INTO `persons` VALUES (918, '姚泓', '姚泓（388年～417年），字元子，京兆郡长安县（今陕西省西安市）人，文桓帝姚兴长子，后秦末代皇帝。');
INSERT INTO `persons` VALUES (919, '乞伏国仁', '乞伏国仁（？～388年），陇西郡襄武县（今甘肃省陇西县）人，鲜卑族。十六国时期西秦开国君主。');
INSERT INTO `persons` VALUES (920, '乞伏暮末', '乞伏暮末（？～431年），字安石跋，陇西郡襄武县（今甘肃省陇西县）人，鲜卑族，秦文昭王乞伏炽磐次子，十六国时期西秦末代君主。');
INSERT INTO `persons` VALUES (921, '吕光', '吕光（337年－400年），字世明，祖籍略阳郡临渭县（今甘肃省秦安县）人，出生于枋头（今河南省浚县），氐族。前秦时期名将、军事家，后凉开国君主。');
INSERT INTO `persons` VALUES (922, '吕隆', '吕隆（？～416年），字永基，略阳郡（今甘肃省天水市）人，后凉武懿帝吕光之侄，后凉末代君主。');
INSERT INTO `persons` VALUES (923, '秃发乌孤', '秃发乌孤（？—399年），河西鲜卑人。十六国时期南凉开国君主。');
INSERT INTO `persons` VALUES (924, '秃发傉檀', '秃发傉檀（365年—415年），河西鲜卑人，鲜卑秃发部首领秃发思复鞬之子，南凉武王秃发乌孤、南凉康王秃发利鹿孤的弟弟，十六国时期南凉末代君主。');
INSERT INTO `persons` VALUES (925, '慕容德', '慕容德（336年～405年），字玄明，昌黎郡棘城县（今辽宁省义县）人，鲜卑族。十六国时期南燕开国皇帝。');
INSERT INTO `persons` VALUES (926, '慕容超', '慕容超（385年～410年），字祖明，祖籍昌黎棘城（今辽宁省义县）人，鲜卑族。南燕末代皇帝。');
INSERT INTO `persons` VALUES (927, '李暠', '李暠（351年～417年），字玄盛，小字长生，陇西狄道人 ，出身陇西李氏。十六国时期西凉开国君主。');
INSERT INTO `persons` VALUES (928, '李恂', '李恂（？～421年），字士如，陇西郡狄道县（今甘肃省临洮县）人，凉武昭王李暠之子，李歆之弟，西凉末代国君。');
INSERT INTO `persons` VALUES (929, '慕容云', '高云（？～409年），字子雨，高句丽族，北燕开国国君，后燕惠愍帝慕容宝养子。');
INSERT INTO `persons` VALUES (930, '冯弘', '冯弘（？～438年），字文通，长乐郡信都县（今河北省衡水市冀州区）人。十六国时期北燕末代国君，文成帝冯跋之弟。');
INSERT INTO `persons` VALUES (931, '赫连勃勃', '赫连勃勃（381年～425年），字屈孑，朔方郡朔方县（今陕西省靖边县）人 。胡夏开国皇帝。');
INSERT INTO `persons` VALUES (932, '赫连定', '赫连定（？～432年），小字直獖，朔方郡朔方县（今陕西省靖边县）人，十六国时期胡夏末代皇帝，先主（武烈帝）赫连勃勃第五子，中主赫连昌之弟。');
INSERT INTO `persons` VALUES (933, '慕容皝', '慕容皝（297年～348年），字元真，小字万年，鲜卑族。昌黎郡棘城县（今辽宁省义县）人，十六国时期前燕开国君主、军事家。');
INSERT INTO `persons` VALUES (934, '慕容儁', '慕容儁（319年～360年），字宣英，鲜卑名贺赖跋，昌黎郡棘城县（今辽宁省义县）人，鲜卑族。前燕开国皇帝。武宣帝慕容廆之孙，文明帝慕容皝第二子，武成帝慕容垂之兄。');
INSERT INTO `persons` VALUES (935, '慕容暐', '慕容暐（350年～384年），字景茂，祖籍昌黎郡棘城县（今辽宁省义县）人，鲜卑族。十六国时期前燕末代皇帝。庸弱无能，奢靡无度。。');
INSERT INTO `persons` VALUES (1001, '拓跋珪', '拓跋珪（371年8月4日～409年11月6日），云中郡盛乐县（今内蒙古和林格尔）人，鲜卑族。北魏王朝开国皇帝、军事家、政治家。昭成帝拓跋什翼犍之孙，献明帝拓跋寔与献明皇后贺氏之子。登国元年（386年），前秦大乱，年仅十五岁的拓跋珪在牛川起兵，击败叔父拓跋窟咄，取得王位继承战争的胜利，光复代国，后改国号为魏。天赐末年，拓拔珪因服用寒食散，逐渐猜忌多疑，对臣下多行诛戮，引起不满。天赐六年十月五日（409年11月6日），其子拓跋绍发起刺杀，拓跋珪遇刺身亡，年仅三十九岁，谥号道武皇帝，庙号太祖。');
INSERT INTO `persons` VALUES (1002, '拓跋嗣', '北魏明元帝拓跋嗣（392年～423年12月24日）,字木末，鲜卑族。北魏王朝第二任皇帝（409年11月10日 ～423年12月24日 在位）。道武帝拓跋珪长子，母为宣穆皇后刘氏。天赐六年（409年），其弟清河王拓跋绍杀父，拓跋嗣入城诛之，即皇帝位，改元永兴。泰常七年（422年），拓跋嗣患病，大封诸王，册立泰平王拓跋焘为皇太子，命其临朝听政，以长孙嵩等人为辅。泰常八年（423年），拓跋嗣驾崩，年仅三十二岁，谥号明元皇帝，庙号太宗，安葬于云中金陵。');
INSERT INTO `persons` VALUES (1003, '拓跋焘', '北魏太武帝拓跋焘（408年～452年3月11日），小字佛厘、佛狸伐。出生于平城东宫（今山西省大同市），鲜卑族。北魏王朝第三位皇帝（423年12月27日～452年3月11日在位）。明元帝拓跋嗣长子，母为明元密皇后杜氏。连年征战导致人民负担沉重，社会矛盾日趋激化，民族反抗和农民起义连续不断。正平二年（452年），拓跋焘为宦官宗爱所杀。谥号太武皇帝，庙号世祖。');
INSERT INTO `persons` VALUES (1004, '拓跋余', '拓跋余（？~452年），字可博真，代郡平城（今山西省大同市）人，鲜卑族。北魏王朝第四位皇帝敬寿帝（452年在位），太武帝拓跋焘之子，景穆帝拓跋晃异母弟，母为闾左昭仪。永平二年（452年），宗爱趁祭祀宗庙之机，谴小黄门贾周将其杀害。拓跋余死后，侄子北魏文成帝拓跋濬即位，诛杀宗爱和贾周等人，以诸侯王的礼仪安葬，谥号为隐。');
INSERT INTO `persons` VALUES (1005, '拓跋濬', '拓跋濬（440年8月4日～465年6月20日），字乌雷，代郡平城（今山西省大同市）人，鲜卑族。北魏王朝第五位皇帝（452年10月31日～465年6月20日在位），太武帝拓跋焘之孙，景穆帝拓跋晃长子，母为恭皇后郁久闾氏。拓跋余遇弑后，即位为帝，年号兴安，诛杀权臣宗爱。和平六年五月癸卯日（465年6月20日），病逝，年仅二十六岁，谥号文成皇帝，庙号高宗，葬于云中金陵。');
INSERT INTO `persons` VALUES (1006, '拓跋弘', '拓跋弘（454年8月14日～476年7月20日），别名第豆胤、万民，出生于阴山，鲜卑族。北魏王朝第六位皇帝（465年6月21日～471年9月20日在位）。文成帝拓跋濬长子，母为文成元皇后。承明元年（476年），拓跋弘于永安殿暴毙（一说被冯太后毒死），年仅二十三岁，谥号献文皇帝，庙号显祖，安葬于金陵。');
INSERT INTO `persons` VALUES (1007, '拓跋宏', '北魏孝文帝拓跋宏（467年10月13日—499年4月26日），鲜卑族，汉名元宏。献文帝拓跋弘长子，生母李夫人。北魏王朝第七位皇帝（471年9月20日—499年4月26日在位），中国古代杰出的少数民族政治家、改革家、文学家。太和二十三年（499年），拓跋宏于军中积劳成疾，驾崩于谷塘原行宫，年仅三十三岁，谥号孝文皇帝，庙号高祖，安葬于长陵。');
INSERT INTO `persons` VALUES (1008, '元恪', '宣武帝元恪（483年～515年），出生于平城（今山西省大同市），鲜卑族。北魏第八位皇帝。孝文帝元宏次子，母为文昭皇后高照容。延昌四年（515年），元恪驾崩，谥号宣武皇帝，庙号世宗，安葬于景陵。');
INSERT INTO `persons` VALUES (1009, '元诩', '元诩（510年4月8日～528年3月31日），河南洛阳人，鲜卑族。宣武帝元恪次子，母为宣武灵皇后胡氏。北魏第九位皇帝（515年～528年在位）。武泰元年（528年），元诩密召尔朱荣率兵入京，试图威胁太后归政于己。事情暴露之后，元诩被胡太后毒害而暴毙身亡，谥号孝明，庙号肃宗，葬于定陵。');
INSERT INTO `persons` VALUES (1010, '元姑娘', '元姑娘（528年2月12日—？），本姓拓跋，河南洛阳人。北魏时期皇女，曾被其祖母胡太后充做皇子拥立为帝。孝明帝元诩和潘充华的女儿，也是孝明帝唯一的骨肉。元姑娘出生后，本应封为公主。父亲孝明帝暴死后，被掌握实权的祖母胡太后谎称皇子，拥立为帝，大赦天下，年号武泰。');
INSERT INTO `persons` VALUES (1011, '元钊', '元钊（526年~528年），字号不详，河南洛阳人，鲜卑族。北魏第十一位皇帝，孝文帝元宏曾孙，临洮王元宝晖之子。孝昌末年，孝明帝元诩突然去世。在灵太后拥立下，元钊即位为帝，天下震惊。建义元年，肆州刺史尔朱荣带兵问罪，制造河阴之变，将幼主元钊沉入黄河淹死。');
INSERT INTO `persons` VALUES (1012, '元子攸', '元子攸（507年—531年1月26日），字彦达，河南洛阳人。北魏第十二位皇帝（528年—531年在位），彭城王元勰第三子。元子攸被尔朱兆俘虏北上，缢杀于晋阳三级佛寺，年仅二十四岁。谥号孝庄皇帝，庙号敬宗，安葬于静陵。');
INSERT INTO `persons` VALUES (1013, '元晔', '元晔（509年—532年12月26日），字华兴，小字盆子，河南洛阳人。北魏王朝第十三位皇帝（530年—531年在位），景穆帝拓跋晃曾孙、南安惠王拓跋桢之孙、扶风王元怡次子。在尔朱世隆拥立下，即位称帝，年号建明，成为傀儡皇帝。');
INSERT INTO `persons` VALUES (1014, '元恭', '元恭（498年～532年），字修业，鲜卑族，南北朝时期北魏第十四任皇帝。广陵惠王元羽之子。普泰元年（531年）二月，被尔朱兆拥立为帝，军国大权完全落入尔朱兄弟之手。次年（532年），高欢攻灭尔朱氏，元恭被废杀，时年三十五岁。西魏权臣宇文泰谥其为节闵皇帝，史称魏前废帝。');
INSERT INTO `persons` VALUES (1015, '元朗', '元朗（513年－532年12月26日），北魏后废帝，字仲哲，河南洛阳人，北魏第十五任皇帝（ 531年10月30日 - 532年6月），章武王元融第三子。高欢信都起兵后，册立为皇帝，年号中兴，迁都邺城。高欢灭亡尔朱氏后，进入河阳，为高欢所废。太昌元年，降封安定郡王，坐事处死，史称后废帝，在位一年。');
INSERT INTO `persons` VALUES (1016, '元修', '元修（510年—535年2月3日），字孝则，河南洛阳人，鲜卑族。北魏末代皇帝，孝文帝元宏之孙，广平武穆王元怀第三子。永?三年十二月十五日（535年2月3日），宇文泰毒杀了元修，时年二十五岁，葬于云陵。西魏追谥为孝武帝，东魏称之为出帝。');
INSERT INTO `persons` VALUES (1017, '元宝炬', '西魏文帝元宝炬（507年—551年3月28日），字子明，鲜卑族。西魏开国皇帝，北魏孝文帝元宏之孙，临洮王元愉之子，母为杨奥妃。大统十七年（551年），元宝炬因病去世，时年四十五岁，安葬于永陵，谥号为文，由皇太子元钦嗣位。');
INSERT INTO `persons` VALUES (1018, '元钦', '元钦（525年～554年），河南洛阳人，鲜卑族。西魏政权第二位皇帝（551年～554年在位），西魏文帝元宝炬嫡长子，母为乙弗皇后。西魏废帝三年（554年），被太师宇文泰毒杀，葬于永陵。');
INSERT INTO `persons` VALUES (1019, '拓跋廓', '拓跋廓（537年～557年），汉名元廓，河南洛阳人，鲜卑族。西魏末代皇帝（554年～556年在位），北魏孝文帝元宏曾孙，西魏文帝元宝炬第四子。西魏恭帝四年（557年），为权臣宇文护所废，降封宋国公，惨遭杀害，谥恭皇帝。');
INSERT INTO `persons` VALUES (1020, '元善见', '元善见（524年～552年1月21日），河南洛阳（今河南省洛阳市）人，鲜卑族。东魏开国皇帝。北魏孝文帝元宏曾孙，清河文宣王元亶之子，母为清河王妃胡智。武定八年（550年），元善见禅位于齐王高洋，降封中山王。天保二年（551年）十二月，元善见被高洋毒杀，时年二十八岁。谥号孝静皇帝，安葬于漳西山岗。东魏亡。');
INSERT INTO `persons` VALUES (1021, '高洋', '北齐文宣帝高洋（526年～559年11月25日），字子进，鲜卑名侯尼于（一作侯尼干），渤海郡蓨县（今河北省景县）人。出生于晋阳，小名晋阳乐。北齐开国皇帝，神武帝高欢嫡次子，文襄帝高澄同母弟，孝昭帝高演、武成帝高湛同母兄，母为武明皇后娄昭君。武定八年（550年），逼迫东魏孝静帝禅位，登基称帝，国号大齐，史称北齐。天保十年，最终饮酒过度而暴毙，时年三十四，庙号显祖，谥号文宣。');
INSERT INTO `persons` VALUES (1022, '高殷', '齐废帝高殷（545年—561年），字正道，小字道人，渤海蓨县（今河北省景县）人。北齐王朝第二位皇帝（559年—560年在位），齐文宣帝高洋嫡长子，母为昭信皇后李祖娥。皇建二年（561年），孝昭帝高演派人将他杀害，年仅十七岁。太宁二年（562年），葬于武宁陵之西北。谥号济南闵悼王。');
INSERT INTO `persons` VALUES (1023, '高演', '高演（535年～561年11月24日），字延安，祖籍渤海郡蓨县（今河北省景县）人，北齐第三位皇帝（560年9月8日—561年11月24日在位）。神武帝高欢第六子，母为武明皇后娄昭君。皇建二年十一月甲辰日（561年11月24日），高演坠马重伤而亡，年仅二十七岁，谥号孝昭皇帝，安葬于文靖陵。');
INSERT INTO `persons` VALUES (1024, '高湛', '高湛（537年～569年1月13日），小字步落稽，祖籍渤海郡蓨县（今河北省景县）人。北齐第四位皇帝。神武帝高欢第九子，母为武明皇后娄昭君。天统四年十二月辛未日（569年1月13日），高湛驾崩，年仅三十二岁，谥号武成皇帝，庙号世祖，安葬于永平陵。');
INSERT INTO `persons` VALUES (1025, '高纬', '高纬（556年5月29日—577年），字仁纲，祖籍渤海郡蓨县（今河北景县）人。北齐第五位皇帝（565年—577年在位）。武成帝高湛次子，母为武成皇后胡氏。北周建德六年（577年）十月，高纬被诬与穆提婆谋反，与安德王高延宗、高恒等人一起被宇文邕赐死，时年二十二岁。大象二年（580年），大丞相杨坚把高纬等人埋葬在长安北原的洪渎川。');
INSERT INTO `persons` VALUES (1026, '高恒', '高恒（570年-578年），即齐幼主，齐后主高纬与皇后穆黄花之子，北齐末代皇帝。建德七年（578年），高恒被北周武帝宇文邕以企图谋反为名，将其处死，年仅七岁。');
INSERT INTO `persons` VALUES (1027, '宇文觉', '宇文觉（542年～557年），字陀罗尼，代郡武川（今内蒙古自治区武川县）人，周文帝宇文泰第三子，母为元皇后，北周开国皇帝，但实际上是权臣宇文护拥立的傀儡。');
INSERT INTO `persons` VALUES (1028, '宇文毓', '宇文毓（534年～560年5月30日），小名统万突，鲜卑族。北周王朝第二位皇帝（557年11月5日～560年5月30日在位），周文帝宇文泰庶长子，母为姚夫人。武成元年（559年），宇文毓正式称皇帝。武成二年（560年），宇文毓为权臣宇文护弑杀，年仅二十七岁，谥号明皇帝，庙号世宗，安葬于昭陵。');
INSERT INTO `persons` VALUES (1029, '宇文邕', '北周武帝宇文邕（543年—578年6月21日），南北朝时期北周第三位皇帝。字祢罗突，鲜卑族，祖籍代郡武川，生于同州（今陕西大荔）。是北周奠基人宇文泰第四子，母文宣皇后叱奴氏（叱奴太后）。宣政元年（578年）五月，周武帝率诸军五道俱进，北伐突厥，因病诏停进军。六月，病重还军长安，当月病逝，年仅三十六岁。谥号武皇帝，庙号高祖，葬于孝陵。');
INSERT INTO `persons` VALUES (1030, '宇文赟', '周宣帝宇文赟（559年～580年6月22日），字乾伯，武乡郡武乡县（今陕西省大荔县）人。北周第四位皇帝（578年6月22日～579年4月1日在位）。周武帝宇文邕长子，母为帝太后李娥姿。病逝，时年二十二岁，谥号宣皇帝，葬于定陵。');
INSERT INTO `persons` VALUES (1031, '宇文阐', '宇文阐（573年8月1日～581年7月10日），原名宇文衍，京兆郡长安县（今陕西省西安市）人，北周王朝末代皇帝（579年4月1日—581年3月4日在位）。周宣帝宇文赟长子，母为天大皇后朱满月。开皇元年（581年），为隋文帝杨坚杀害，年仅九岁，谥号静皇帝，葬于恭陵。杨坚废静帝宇文阐，建立隋朝，北周灭亡。');
INSERT INTO `persons` VALUES (1101, '刘裕', '他是刘宋的开国皇帝，出身贫寒，凭借自身军事才能，对内平定桓玄之乱、消灭卢循、刘毅等割据势力，统一南方；对外北伐，灭南燕、后秦，收复洛阳、长安等地，代晋称帝后，加强中央集权，开创了 “元嘉之治” 的良好开端。');
INSERT INTO `persons` VALUES (1102, '刘义符', '刘义符（406年—424年8月4日），小字车兵，祖籍彭城郡彭城县（今江苏省徐州市）。南朝宋第二位皇帝，宋武帝刘裕长子，母为张夫人');
INSERT INTO `persons` VALUES (1103, '刘义隆', '刘义隆（407年～453年），小字车儿，祖籍徐州彭城郡（今江苏省徐州市）人，出生于京口（今江苏省镇江市）。南朝宋第三位皇帝、文学家，宋武帝刘裕第三子，母为文章太后胡道安。');
INSERT INTO `persons` VALUES (1104, '刘劭', '刘劭（424年～453年），字休远，宋文帝刘义隆嫡长子，母为皇后袁齐妫。南朝宋第四任皇帝。');
INSERT INTO `persons` VALUES (1105, '', '刘骏（430年9月19日－464年7月12日），字休龙，小字道民，徐州彭城郡彭城县（今江苏省徐州市铜山区）人。南北朝时期政治家，刘宋第五位皇帝（453年5月20日－464年7月12日在位，一说为第四位皇帝），宋文帝刘义隆第三子，宋明帝刘彧异母兄，母为路惠男。');
INSERT INTO `persons` VALUES (1106, '刘子业', '刘子业（449年～466年），小字法师，祖籍彭城郡彭城县（今江苏省徐州市）人。南北朝时期著名暴君，南朝宋第六位皇帝、宋孝武帝刘骏长子，母为文穆皇后王宪嫄。');
INSERT INTO `persons` VALUES (1107, '刘彧', '刘彧（439年～472年），字休炳，小字荣期，徐州彭城郡彭城县（今江苏省徐州市）人。南朝宋第七位皇帝，宋武帝刘裕的孙子，宋文帝刘义隆第十一子，宋孝武帝刘骏异母弟，母为沈容姬。');
INSERT INTO `persons` VALUES (1108, '刘昱', '刘昱（463年3月1日~477年8月1日），字德融，小字慧震，宋明帝长子，南朝宋第八位皇帝。');
INSERT INTO `persons` VALUES (1109, '刘准', '刘准（467年8月8日——479年6月23日），字仲谋，小字智观，刘宋王朝末代皇帝，宋明帝刘彧第三子（一说为桂阳王刘休范之子）。');
INSERT INTO `persons` VALUES (1110, '萧道成', '齐高帝萧道成（427年—482年4月11日），字绍伯，小字斗将，祖籍东海郡兰陵县（今山东省临沂市兰陵县），后定居晋陵郡武进县，为南兰陵郡（今丹阳经济开发区张巷行政村东城村）人 ，南朝齐开国皇帝（479年5月29日—482年4月11日在位）。');
INSERT INTO `persons` VALUES (1111, '萧赜', '萧赜（440年—493年），小名龙儿，字宣远，祖籍南兰陵郡（今江苏省常州市）人，出生于建康（今江苏省南京市）。齐高帝萧道成长子，母为刘智容。南朝齐第二任皇帝（482年―493年在位）。');
INSERT INTO `persons` VALUES (1112, '萧昭业', '萧昭业（473年～494年9月7日），字元尚，小字法身，丹阳郡建康县（今江苏省南京市）人。南朝齐第三任皇帝，齐武帝萧赜的孙子，文惠太子萧长懋长子 ，母为文安皇后王宝明。');
INSERT INTO `persons` VALUES (1113, '萧鸾', '萧鸾（452年－498年9月1日），即齐明帝，字景栖，小字玄度，南兰陵郡兰陵县（今江苏省常州市武进区）人，南朝齐第五任皇帝（494年12月22日－498年9月1日在位），齐高帝萧道成的侄子，始安贞王萧道生的次子。');
INSERT INTO `persons` VALUES (1114, '萧宝卷', '萧宝卷（483年～501年12月31日），即东昏侯（南史也作齐废帝），字智藏，本名明贤，南兰陵郡兰陵县（今江苏省常州市）人，南朝齐第六任皇帝（498年9月1日～501年12月31日）。齐明帝萧鸾的次子。');
INSERT INTO `persons` VALUES (1115, '萧宝融', '萧宝融（488年-502年），即齐和帝。字智昭，明帝第八子。');
INSERT INTO `persons` VALUES (1116, '萧衍', '梁武帝萧衍（464年－549年6月12日），字叔达，小字练儿，南兰陵郡东城里（今属江苏省常州市）人。南朝梁开国皇帝（502年4月30日－549年6月12日在位） ，西汉相国萧何的二十五世孙，南齐丹阳尹萧顺之之子。');
INSERT INTO `persons` VALUES (1117, '萧纲', '萧纲（503年12月2日—551年11月15日），字世赞（一说世缵），小字六通，生于建康宫显阳殿（今江苏省南京市） ，南北朝时期南梁第二位皇帝、梁武帝萧衍第三子，昭明太子萧统同母弟，母为贵嫔丁令光。');
INSERT INTO `persons` VALUES (1118, '萧栋', '萧栋（？～552年），字元吉，南兰陵郡兰陵县（今江苏省常州市武进区）人。南梁第三位皇帝，梁武帝萧衍曾孙、昭明太子萧统之孙、豫章安王萧欢之子。');
INSERT INTO `persons` VALUES (1119, '萧纪', '萧纪（508年～553年），字世询，生于建康宫（今江苏省南京市），南梁皇帝，梁武帝萧衍第八子，母葛修容，梁元帝萧绎之弟。');
INSERT INTO `persons` VALUES (1120, '', '梁元帝萧绎（508年9月16日~555年1月27日），字世诚，小字七符，号金楼子，南兰陵郡兰陵县（今江苏省常州市武进区）人。南朝梁第四位皇帝、文学家、画家， 梁武帝萧衍第七子，母为阮令嬴。');
INSERT INTO `persons` VALUES (1121, '萧渊明', '萧渊明（？~556年6月2日），字靖通，南兰陵郡兰陵县（今江苏省常州市）人。南朝梁第五位皇帝。梁文帝萧顺之之孙，长沙宣武王萧懿之子，梁武帝萧衍之侄。');
INSERT INTO `persons` VALUES (1122, '萧方智', '萧方智（543年－558年5月5日），字慧相，南梁末代皇帝，梁元帝萧绎第九子，母为夏贤妃。');
INSERT INTO `persons` VALUES (1123, '萧庄', '萧庄（548年—577年），南朝梁宗室，梁元帝萧绎之孙、武烈太子萧方等之子。');
INSERT INTO `persons` VALUES (1124, '陈霸先', '陈霸先（503年～559年8月9日），即陈武帝，字兴国，小字法生，吴兴郡（今浙江省长兴县）长城下若里人。南北朝时期陈朝开国皇帝（557年11月16日～559年8月9日在位）。');
INSERT INTO `persons` VALUES (1125, '陈蒨', '陈文帝陈蒨（522年～566年5月31日），本名陈昙蒨，字子华，号荃菺，吴兴郡长城县（今浙江省长兴县）人。南朝陈第二位皇帝、政治家。武帝陈霸先之侄，始兴昭烈王陈道谭长子，宣帝陈顼之兄。');
INSERT INTO `persons` VALUES (1126, '陈伯宗', '陈伯宗（554年6月20日－570年4月22日），字奉业，小字药王，陈文帝陈蒨的嫡长子，母安德皇后沈妙容，南陈第三位皇帝。');
INSERT INTO `persons` VALUES (1127, '陈顼', '陈顼（530年8月14日 [6]-582年2月17日）， 本名陈昙顼，字绍世，小字师利。籍贯吴兴长城（今浙江省长兴县）。始兴昭烈王陈道谭次子，陈武帝陈霸先之侄，陈文帝陈蒨的弟弟。南朝陈第四位皇帝（569年2月5日-582年2月17日在位）。');
INSERT INTO `persons` VALUES (1128, '陈叔宝', '陈后主陈叔宝（553年12月10日—604年12月16日），字元秀，小字黄奴，吴兴长城（今浙江长兴东人）。 陈宣帝陈顼与皇后柳敬言之子，南北朝时期陈朝最后一位皇帝。');
INSERT INTO `persons` VALUES (1201, ' 隋文帝 ', '隋文帝杨坚（541 年 7 月 21 日 - 604 年 8 月 13 日），隋朝开国皇帝。汉太尉杨震十四世孙，代周建隋，统一全国，开创 “开皇之治”。');
INSERT INTO `persons` VALUES (1202, ' 隋炀帝 ', ' 隋世祖杨广（569 年 - 618 年 4 月 11 日），隋朝第二位皇帝。参与平陈，即位后修建运河、开拓疆土，但因滥用民力致隋亡。');
INSERT INTO `persons` VALUES (1203, ' 隋恭帝 ', ' 隋恭帝杨侑（605 年 - 619 年），隋炀帝之孙。李渊入长安后被立为帝，后禅位，隋朝灭亡。');
INSERT INTO `persons` VALUES (1204, ' 杨浩 ', ' 杨浩（？ - 618 年），隋文帝之孙。宇文化及弑杀杨广后被立为帝，后被宇文化及废杀。');
INSERT INTO `persons` VALUES (1205, ' 杨侗 ', ' 杨侗（604 年 - 619 年），隋炀帝之孙。留守东都，曾与瓦岗军作战，后被王世充拥立，最终遇害。');
INSERT INTO `persons` VALUES (1301, '李渊', '李渊（566年12月21日－635年6月25日），字叔德。中国唐朝开国皇帝（618年6月18日－626年9月3日在位），初唐政治家、军事统帅，唐太祖李虎之孙，唐世祖李昞之子。贞观九年（635年），李渊病逝，享年七十岁。谥号太[大]武皇帝，庙号高祖，葬于献陵。');
INSERT INTO `persons` VALUES (1302, '李世民', '唐太宗李世民（599年1月23日—649年7月10日），唐高祖次子，生于武功（今陕西武功）。祖籍陇西成纪（今甘肃秦安），一说陇西狄道（今甘肃省临洮县）人，又说钜鹿郡人。唐朝第二位皇帝（626年9月3日—649年7月10日在位），政治家、战略家、军事家、书法家、诗人。贞观二十三年五月己巳日（649年7月10日），李世民驾崩于含风殿，享年五十二岁，在位二十三年，庙号唐太宗，谥号文皇帝（后加谥文武大圣大广孝皇帝），葬于昭陵。');
INSERT INTO `persons` VALUES (1303, '李治', '唐高宗李治（628年7月21日-683年12月27日），字为善，唐朝第三位皇帝（649年7月15日-683年12月27日在位），唐太宗李世民第九子，母为长孙皇后。683年12月27日，李治驾崩于洛阳贞观殿，享年五十六岁，葬于乾陵。庙号高宗，谥号天皇大帝。');
INSERT INTO `persons` VALUES (1304, '李显', '唐中宗李显（656年11月26日—710年7月3日），原名李哲，唐朝第四位皇帝，唐高宗李治第七子，武则天第三子。唐中宗李显前后两次当政，共在位五年半，景龙四年六月壬午日（710年7月3日）被韦皇后和安乐公主毒死，终年55岁，谥号大和大圣大昭孝皇帝，庙号中宗，葬于定陵。');
INSERT INTO `persons` VALUES (1305, '李旦', '唐睿宗李旦（662年6月22日－716年7月13日），曾用名李旭轮、李轮、武轮，唐高宗李治第八子，武则天幼子，唐朝第五位皇帝。先天元年（712年），李旦退位为太上皇，然大政仍自掌，太子李隆基继皇帝位。次年，李隆基诛杀太平公主及其同党，始全部归政。开元四年（716年）崩，年55岁，葬于桥陵。');
INSERT INTO `persons` VALUES (1306, '李重茂', '唐少帝李重茂（695年－714年），陇西成纪（今甘肃省秦安县）人。唐朝第六位皇帝，唐中宗李显第四子。景龙四年（710年），即皇帝位，嫡母韦皇后临朝称制，年号唐隆。开元二年（714年），出任房州刺史，在任上逝世，时年二十岁，谥号为殇，葬在武功县西原。');
INSERT INTO `persons` VALUES (1307, '李隆基', '唐玄宗李隆基（685年9月8日—762年5月3日），唐高宗李治与武则天之孙，唐睿宗李旦第三子，故又称李三郎，母窦德妃。唐朝在位最长的皇帝（712年9月8日—756年8月12日在位）。宝应元年四月甲寅日（762年5月3日），病逝于长安神龙殿，终年78岁，谥号至道大圣大明孝皇帝，庙号玄宗（清朝为避清圣祖讳，改为元宗），葬于泰陵。');
INSERT INTO `persons` VALUES (1308, '李亨', '唐肃宗李亨（711年10月19日—762年5月16日），又名李嗣升、李浚、李玙、李绍，庙号肃宗，是唐玄宗李隆基的第三子，母为元献皇后杨氏，唐代第八位皇帝（756年—762年在位）。宝应元年（762年）四月，李亨病死，时年五十二岁。庙号肃宗，谥号文明武德大圣大宣孝皇帝，葬于建陵。');
INSERT INTO `persons` VALUES (1309, '李豫', '唐代宗李豫（726年11月11日－779年6月10日），初名李俶[chù]，陇西狄道（今甘肃省临洮县）人。唐朝第九位皇帝（762年5月18日－779年6月10日在位），唐肃宗李亨长子，母为章敬皇后吴氏。大历十四年（779年），李豫于大明宫紫宸内殿崩逝。谥号睿文孝武皇帝，庙号代宗（实为世宗），葬于元陵。');
INSERT INTO `persons` VALUES (1310, '李适', '李适[kuò]（742年5月27日—805年2月25日），小名岧郎 ，祖籍陇西成纪（今甘肃省天水市秦安县），唐朝第十位皇帝，唐代宗李豫长子，母为睿真皇后沈氏。贞元二十一年（805年），李适于会宁殿驾崩，享年六十四岁，在位二十七年。谥号神武孝文皇帝，庙号德宗，葬于崇陵。');
INSERT INTO `persons` VALUES (1311, '李诵', '唐顺宗李诵（761年—806年），祖籍陇西狄道（今甘肃省临洮县）。唐朝第十一位皇帝，唐德宗李适长子，母亲为昭德皇后王氏。贞元二十一年（805年）正式继位。即位后，立即重用王叔文等推行改革，抑制宦官。同年8月，宦官逼迫李诵退位，让其禅位于太子李纯。次年，李诵病死，终年46岁。');
INSERT INTO `persons` VALUES (1312, '李纯', '唐宪宗李纯（778年—820年），初名淳，后改名纯，唐顺宗李诵长子，唐德宗李适的孙子。中国唐朝第十二位皇帝[除去唐殇帝]（805年—820年在位）。元和十五年（820年），李纯为宦官陈弘志等人谋杀，享年四十三岁。谥号圣神章武孝皇帝，庙号宪宗。葬于景陵。');
INSERT INTO `persons` VALUES (1313, '李恒', '唐穆宗李恒（795年7月26日-824年2月25日），初名李宥，唐朝第十三任皇帝，唐宪宗李纯第三子。长庆四年（824年）正月，服食金丹，因故驾崩，享年三十，谥号“睿圣文惠孝皇帝\\”。');
INSERT INTO `persons` VALUES (1314, '李湛', '唐敬宗李湛（809年7月22日—827年1月9日），陇西成纪（今甘肃省秦安县）人。唐朝第十四位皇帝（824年—827年在位），唐穆宗李恒长子，母为恭僖皇后王氏。宝历二年十二月初八辛丑日（827年1月9日），为宦官刘克明等所弑，年仅十八岁，谥号“睿武昭愍孝皇帝\\”，庙号敬宗，葬于庄陵。');
INSERT INTO `persons` VALUES (1315, '李昂', '唐文宗李昂（809年11月20日－840年2月10日），原名李涵，唐朝第十五位皇帝，唐穆宗李恒的次子，母为贞献皇后萧氏。开成五年（840年），李昂抑郁而终，年仅三十二岁，谥号元圣昭献孝皇帝，庙号文宗，安葬于章陵。');
INSERT INTO `persons` VALUES (1316, '李炎', '唐武宗李炎（814年7月2日-846年4月22日），曾名李瀍。唐文宗之弟，唐穆宗与宣懿皇后韦氏之子，唐朝第十六位皇帝。');
INSERT INTO `persons` VALUES (1317, '李忱', '唐宣宗李忱，初名李怡，唐朝第十七位皇帝。唐宪宗之子，唐穆宗异母弟。在位时勤于政事，整顿吏治，限制宗室与宦官，恢复佛寺，对外击败吐蕃等，开创 “大中之治\\”，因服长生药中毒驾崩。');
INSERT INTO `persons` VALUES (1318, '李漼', '唐懿宗李漼，原名温，唐宣宗长子。在位时怠于政事，喜宴游，宠信宦官，所用宰相多非其人，政治腐败，民不聊生，各地动乱频发，病卒时年仅四十一岁。');
INSERT INTO `persons` VALUES (1319, '李儇', '唐僖宗李儇，本名李俨，唐懿宗第五子。12 岁即位，权宦田令孜把持朝政，引发王仙芝、黄巢起义，曾逃亡蜀地，末年节度使割据，唐朝分裂，27 岁去世。');
INSERT INTO `persons` VALUES (1320, '李晔', '唐昭宗李晔，曾用名杰、敏，唐懿宗第七子，唐僖宗之弟。在位致力于振兴国威，打击割据势力、宦官势力，却多次被迫逃离京城，后为朱温部将所杀，未能挽救唐朝颓势。');
INSERT INTO `persons` VALUES (1321, '李柷', '唐哀帝李柷，初名祚，唐昭宗第九子。乾宁四年封辉王，天祐元年，朱温弑唐昭宗后，他被矫诏拥立为帝，后唐朝灭亡。');
INSERT INTO `persons` VALUES (1401, ' 朱温 ', ' 宋州砀山（今安徽砀山 ）人，出身低微。早年参加黄巢起义军，后归降唐朝，被赐名 \"朱全忠\" ，任宣武军节度使。凭借军事才能和权谋，在唐末藩镇混战中逐渐壮大，成为最大割据势力。天祐四年（907 年 ），接受唐哀帝禅位，代唐称帝，建国号梁，改元开平，史称后梁。称帝初轻徭薄赋，但在与晋王李存勖的争霸中屡处下风。乾化二年（912 年 ），因继位问题被次子朱友珪谋杀，享年六十一岁 ，谥号神武元圣孝皇帝，庙号太祖，葬于宣陵。');
INSERT INTO `persons` VALUES (1402, ' 朱友珪 ', ' 朱温第三子，乾化二年（912 年 ），弑父篡位，改元凤历。朱友珪得位不正，人心不服。他荒淫无度，致使政治更加黑暗混乱。乾化三年（913 年 ）二月，被其四弟朱友贞联合禁军讨灭 ，在位仅一年，死时 29 岁 ，被废为庶人。');
INSERT INTO `persons` VALUES (1403, ' 朱友贞 ', ' 朱温第四子，朱友珪被杀后，他在开封被拥立为帝，是为梁末帝，改元乾化。在位时信用奸臣，老臣遭排挤，内部起义不断，国势江河日下。后唐李存勖趁机进攻，同光元年（923 年 ）十月，唐军进逼后梁东都汴州，朱友贞见城破在即，命禁军将领将自己杀死，后梁灭亡 ，死时 36 岁 。');
INSERT INTO `persons` VALUES (1404, ' 李存勖 ', ' 本姓朱邪氏，沙陀族，是晋王李克用长子。自幼善骑射、胆略过人，喜读《春秋》 。908 年承继晋王之位，对内平李克宁之乱，稳固政局；对外以复兴唐朝为名与后梁争雄，破桀燕、败契丹，扭转与后梁攻防态势。923 年四月称帝建后唐，同年灭后梁，又伐灭前蜀，开拓疆土。为政时政治上模仿唐末旧制，重用伶宦、以门第取仕、纵容皇后干政；经济上前期轻徭薄赋，后设租庸使重敛百姓；文化上设史馆、求书籍。后期沉湎声色，治国乏术，猜忌杀戮功臣，致军心离散、百姓困苦。926 年，因西川兵变、邺都兵变，李嗣源反叛，禁军将领郭从谦发动兴教门兵变，李存勖死于流矢，庙号庄宗，谥号光圣神闵孝皇帝 ，葬于雍陵。');
INSERT INTO `persons` VALUES (1405, ' 李嗣源 ', ' 李克用养子，沙陀族。初为骑兵，作战勇猛，屡立战功。李存勖在位时任蕃汉内外马步军总管。926 年李存勖死后，他在众人拥戴下即位。在位期间革除庄宗弊政，诛杀酷吏孔谦，废除苛敛，精简宫廷人员，与民休息，使社会生产得到一定恢复，局势渐趋稳定。但他晚年也面临诸多问题，诸子争位，朝政混乱。933 年，李嗣源病重，次子李从荣举兵夺位被杀，他受惊吓而死 ，庙号明宗，谥号圣德和武钦孝皇帝，葬于徽陵。');
INSERT INTO `persons` VALUES (1406, ' 李从厚 ', ' 李嗣源第三子，933 年李嗣源死后继位。他在位时，为加强中央集权，急于削弱藩镇势力，引起地方节度使不满。934 年，潞王李从珂在凤翔起兵反叛，李从厚派军征讨却战败，后在出逃途中被石敬瑭劫持至卫州，不久被李从珂派人所杀，年仅 21 岁，谥号愍皇帝 ，无庙号。');
INSERT INTO `persons` VALUES (1407, ' 李从珂 ', ' 本姓王，李嗣源养子，身材魁梧、骁勇善战。934 年反叛成功后即皇帝位。他在位时，后唐内部矛盾重重，外部石敬瑭势力崛起。936 年，石敬瑭在契丹支持下起兵反唐，唐军抵挡不住。同年闰十一月，李从珂见大势已去，带着传国玉玺与曹太后等登上玄武楼自焚而死 ，后唐灭亡，无谥号及庙号。');
INSERT INTO `persons` VALUES (1408, ' 石敬瑭 ', '892 年生于太原汾阳里，沙陀族。初隶李嗣源，作战骁勇。后掌握河东军政，因与李从珂互忌，936 年以割让燕云十六州、称 “儿皇帝\\” 为条件借契丹之力称帝，建立后晋，灭后唐。在位时因向契丹称臣引发内乱，942 年忧郁而死，庙号高祖。');
INSERT INTO `persons` VALUES (1409, ' 石重贵 ', ' 石敬瑭之侄，942 年继位。继位后不再向契丹称臣，双方交恶。契丹多次南下，后晋因用人不当、灾害频发难以抵御，947 年都城被契丹攻占，石重贵投降，后晋亡，其被迁北方，974 年逝于建州。');
INSERT INTO `persons` VALUES (1410, ' 刘知远 ', '895 年生于太原府，沙陀族。早年追随石敬瑭，后晋时为重要藩镇。947 年契丹灭后晋后，刘知远在太原称帝，后改国号为汉，统一黄河流域。因任用酷吏、拉拢藩镇，留下隐患，948 年病逝，庙号高祖。');
INSERT INTO `persons` VALUES (1411, ' 刘承祐 ', ' 刘知远次子，948 年继位。在位时命郭威平藩镇叛乱，后猜忌大臣。950 年因欲杀郭威，致其反叛，刘承祐出逃时被溃军所杀，后汉灭亡，年仅 20 岁。');
INSERT INTO `persons` VALUES (1412, ' 郭威 ', ' 邢州尧山人，身材魁梧，早年为牙兵，协助刘知远称帝。因遭后汉隐帝猜忌，发动兵变，951 年称帝建后周。在位时革除积弊，重用文臣，崇尚节俭，恢复生产。954 年病逝，庙号太祖。');
INSERT INTO `persons` VALUES (1413, ' 柴荣 ', ' 邢州尧山人，郭威养子。继位后改革政治，整军经武，亲征高平败北汉与辽联军，收复后蜀土地，三征南唐，北征辽朝。959 年商议取幽州时患病去世，庙号世宗。');
INSERT INTO `persons` VALUES (1414, ' 柴宗训 ', ' 柴荣第四子，7 岁继位，由符太后垂帘听政。960 年陈桥兵变后，被迫禅位给赵匡胤，后周亡。被降封郑王，973 年去世。');
INSERT INTO `persons` VALUES (1415, ' 王建 ', ' 许州舞阳人，早年贩私盐后投军，凭镇压起义崛起，得唐信任。占蜀地封王，907 年称帝建前蜀。前期兴农爱才，后期猜忌，重用宦官，918 年病故，庙号高祖。');
INSERT INTO `persons` VALUES (1416, ' 王衍 ', ' 王建十一子，受宠妃影响被立为太子，继位后荒淫，委政他人，奢侈卖官。925 年后唐灭前蜀，王衍出降被杀，年二十八。');
INSERT INTO `persons` VALUES (1417, ' 孟知祥 ', ' 邢州龙冈人，早年得李克用赏识，娶李克让之女。925 年征前蜀后任西川节度使，后唐内乱时据蜀，933 年封蜀王，934 年称帝建后蜀。在位整顿吏治、轻税赋、促生产，仅半年即病逝，庙号高祖。');
INSERT INTO `persons` VALUES (1418, ' 孟昶 ', ' 孟知祥第三子，继位初励精图治，国势强盛，后期沉湎酒色，朝政腐败。964 年北宋伐蜀，孟昶出降，后蜀亡，被俘至开封后卒，年 47 岁。他推动了文学、绘画、雕版印书等文化发展。');
INSERT INTO `persons` VALUES (1419, ' 杨行密 ', ' 庐州合肥人，早年参加叛乱后为州兵，立功升迁，占庐州被封刺史，控江淮。902 年封吴王建吴国。在位招抚流民、轻徭薄赋恢复经济，重军事建设御外敌，905 年去世，后追尊为武皇帝，庙号太祖。');
INSERT INTO `persons` VALUES (1420, ' 杨渥 ', ' 杨行密长子，杨行密去世后继位。骄横奢侈，亲信不法，引将领不满。907 年张颢、徐温兵变，908 年被张颢所杀，后被追谥为景皇帝，庙号烈祖。');
INSERT INTO `persons` VALUES (1421, ' 杨隆演 ', ' 杨行密次子，杨渥被杀后被拥立。在位时政权在徐温手中，无实权，因大权旁落抑郁，放纵致生病卧床，921 年去世，后被追尊为宣皇帝，庙号高祖。');
INSERT INTO `persons` VALUES (1422, ' 杨溥 ', ' 杨行密第四子，杨隆演死后被立为王，徐温死后称帝。在位时徐知诰掌大权，937 年禅位，吴国亡，被降为让皇，后死于丹阳，谥号睿皇帝。');
INSERT INTO `persons` VALUES (1423, ' 李昪 ', ' 原徐知诰，徐温养子，937 年废吴帝建大齐，939 年复李姓改国号唐，称是李恪四世孙。在位招贤纳能，慎刑狱，重文轻武，轻徭薄赋，息兵安境，巩固发展政权与生产，943 年去世。');
INSERT INTO `persons` VALUES (1424, ' 李璟 ', ' 李昪长子，继位后灭闽、楚扩土，耗虚府库。后广置屯田，改革措施却加剧社会矛盾。遭后周南征屡败，去帝号称国主并称臣，961 年迁都南昌后病逝。');
INSERT INTO `persons` VALUES (1425, ' 李煜 ', ' 李璟第六子，李璟病逝后继位。即位后改革弊政，后去国号称江南国主。975 年宋军破金陵，李煜出降，南唐亡，被俘至汴京被封违命侯后遭毒死。');
INSERT INTO `persons` VALUES (1426, ' 钱镠 ', '907 年受后梁太祖朱温封吴越王，923 年被册封为吴越国王，建吴越国。在位保境安民，兴修钱塘江海塘，鼓励垦田，经济繁荣，有 “钱塘富庶盛于东南\\” 之誉。932 年去世，谥号武肃王，庙号太祖。');
INSERT INTO `persons` VALUES (1427, ' 钱元瓘 ', ' 钱镠第五子，932 年继位。遵先王命尊奉中原，任曹仲达理政，设择能院选官，劝课农桑。941 年因杭州城火灾受惊病逝，谥号文穆王。');
INSERT INTO `persons` VALUES (1428, ' 钱弘佐 ', ' 钱元瓘第六子，941 年继位。任用贤人，轻徭薄赋。945 年力排众议发兵救福州获胜，保边境安宁，947 年去世，谥号忠献王，庙号成宗。');
INSERT INTO `persons` VALUES (1429, ' 钱弘倧 ', ' 钱元瓘第七子，947 年继位。同年十二月，内衙指挥使胡进思发动政变，被囚后王位传予其弟钱弘俶。');
INSERT INTO `persons` VALUES (1430, ' 钱弘俶 ', ' 钱元瓘第九子，948 年继位。免百姓赋税，分荒田予民耕种。978 年 “纳土归宋\\”，吴越国亡。');
INSERT INTO `persons` VALUES (1431, ' 王延钧 ', ' 王审知次子，927 年杀王延翰夺位，更名王璘，933 年称帝建大闽，都长乐府。好鬼神道家，重用奸臣，残害贤良。935 年被李仿与王继鹏合谋所杀。');
INSERT INTO `persons` VALUES (1432, ' 王继鹏 ', ' 王延钧长子，王延钧死后自立为闽帝。迷信道教，纵容道士卖官。939 年遭连重遇、朱文进兵变，出逃后被王延羲、王继业捕杀。');
INSERT INTO `persons` VALUES (1433, ' 王延羲 ', ' 王审知少子，939 年王昶被杀后继位。不容王延政致其出走建州，941 年称帝。在位时闽国政治腐败，国力衰退。');
INSERT INTO `persons` VALUES (1434, ' 王延政 ', ' 王审知之子，943 年在建州称帝建大殷，闽国分裂。944 年收复故土复国号闽，945 年南唐破建州被俘，闽国亡。');
INSERT INTO `persons` VALUES (1435, ' 马殷 ', ' 早年为木匠，从军后统一湖南，获唐廷授职。907 年封楚王，927 年正式建国。在位保境安民，兴农商、重贸易，促楚国经济发展。930 年去世，谥号武穆王，其死后楚国因内斗衰落，951 年被南唐所灭。');
INSERT INTO `persons` VALUES (1436, ' 刘? ', ' 南汉开国皇帝，917 年称帝，前期仿唐制革新，后期骄奢荒淫，942 年病逝，庙号高祖。');
INSERT INTO `persons` VALUES (1437, ' 刘玢 ', ' 刘?长子，继位后骄奢荒淫，不理政事，943 年被刘弘熙所杀，谥号殇帝。');
INSERT INTO `persons` VALUES (1438, ' 刘晟 ', ' 刘?第四子，杀兄称帝，诛杀宗室，任用宦官，扩张疆域后晚年享乐，958 年去世，庙号中宗。');
INSERT INTO `persons` VALUES (1439, ' 刘鋹 ', ' 刘晟长子，在位宦官专权，诛杀宗室，加重税赋，971 年宋军南下时投降，南汉灭亡。');
INSERT INTO `persons` VALUES (1440, ' 高季兴 ', ' 南平开国君主，早年为家奴后成朱温牙将，907 年任荆南节度使，后投后唐封南平王。在荆南与民休息，也抢夺财物，929 年去世，谥号武信。');
INSERT INTO `persons` VALUES (1441, ' 高从诲 ', ' 高季兴长子，929 年袭位。礼贤下士，省刑轻赋，使百姓安定，向多国称臣求赏，被称 “高赖子\\”，948 年去世，谥号文献。');
INSERT INTO `persons` VALUES (1442, ' 高保融 ', ' 高从诲长子，948 年即位，在位时国力强，个性懦弱委政于弟高保勖，960 年去世，谥号贞懿。');
INSERT INTO `persons` VALUES (1443, ' 高保勖 ', ' 高从诲第十子，960 年即位，在位内乱不断，国力渐衰，962 年去世，谥号康定。');
INSERT INTO `persons` VALUES (1444, ' 高继冲 ', ' 高保融之子，962 年被高保勖任节度使，963 年宋军南下纳地归降，南平灭亡。');
INSERT INTO `persons` VALUES (1445, ' 刘崇', ' 后汉高祖刘知远之弟，950 年郭威称帝后在太原称帝建立北汉，向辽乞援约为父子之国，954 年高平之战大败后病逝，在位 3 年，庙号世祖。');
INSERT INTO `persons` VALUES (1446, ' 刘钧', ' 刘崇次子，954 年继位，受辽册封，性格恭谨，勤政爱民，境内安定，后因辽宋压力忧愤成疾，968 年去世，在位 14 年，庙号睿宗。');
INSERT INTO `persons` VALUES (1447, ' 刘继恩 ', ' 刘钧养子，本姓薛，968 年继位，在位 60 天，欲杀权臣郭无为反被其派侯霸荣所杀，享年 34 岁。');
INSERT INTO `persons` VALUES (1448, ' 刘继元 ', ' 本姓何，刘钧外甥、养子，968 年被郭无为迎立为帝，信用奸小，残忍嗜杀，政事混乱，979 年宋太宗亲征时投降，北汉灭亡，在位 11 年。');
INSERT INTO `persons` VALUES (1501, '宋太祖', ' 宋太祖赵匡胤（927 - 976 年），宋朝开国皇帝。通过陈桥兵变称帝，结束五代十国分裂。在位期间统一大部，加强中央集权，奠定宋朝统治基础。');
INSERT INTO `persons` VALUES (1502, '宋太宗', ' 宋太宗赵炅（939 - 997 年），宋朝第二位皇帝。继承兄业，完成统一中原。亲征太原灭北汉，但对辽战争失利，奉行守内虚外政策，进一步强化中央集权。');
INSERT INTO `persons` VALUES (1503, '宋真宗', ' 宋真宗赵恒（968 - 1022 年），宋朝第三位皇帝。前期促成 “咸平之治”，与辽达成 “澶渊之盟”；后期沉溺封禅，广建宫观，致使社会矛盾加深。');
INSERT INTO `persons` VALUES (1504, '宋仁宗', ' 宋仁宗赵祯（1010 - 1063 年），宋朝第四位皇帝。在位四十二 年，知人善任，推行 “庆历新政”，北宋经济繁荣，文化昌盛，史称 “仁宗盛治”。');
INSERT INTO `persons` VALUES (1505, '宋英宗', ' 宋英宗赵曙（1032 - 1067 年），宋朝第五位皇帝。任用前朝改革派，继续推进部分弊政改革，重视书籍编写整理，命司马光专修《资治通鉴》。');
INSERT INTO `persons` VALUES (1506, '宋神宗', ' 宋神宗赵顼（1048 - 1085 年），宋朝第六位皇帝。支持王安石变法，力图富国强兵；进行官制改革；有统一之志，但军事改革成效有限，对辽、西夏战争未达预期。');
INSERT INTO `persons` VALUES (1507, '宋哲宗', ' 宋哲宗赵煦（1077 - 1100 年），宋朝第七位皇帝。亲政后恢复新法，对外击败西夏；但无法阻止党争，英年早逝，其统治使宋朝国势有一定起色。');
INSERT INTO `persons` VALUES (1508, '宋徽宗', ' 宋徽宗赵佶（1082 - 1135 年），宋朝第八位皇帝。政治上昏庸，重用奸臣，统治腐朽致农民起义频发；艺术造诣极高，创 “瘦金体”，推动宫廷绘画发展。');
INSERT INTO `persons` VALUES (1509, '宋钦宗', ' 宋钦宗赵桓（1100 - 1156 年），宋朝第九位皇帝，北宋末代皇帝。在位时向金屈辱求和，最终与宋徽宗一同被金兵掳去，北宋灭亡。');
INSERT INTO `persons` VALUES (1510, '宋高宗', ' 宋高宗赵构（1107 - 1187 年），南宋开国皇帝。建立南宋，与金媾和维持偏安；重用秦桧，杀害岳飞；精通书法，引领南宋书风。');
INSERT INTO `persons` VALUES (1511, '宋孝宗', ' 宋孝宗赵昚（1127 - 1194 年），南宋第二位皇帝。锐意恢复中原，发动 “隆兴北伐”；注重内政，整顿吏治，造就 “乾淳之治”，被称南宋最贤明皇帝。');
INSERT INTO `persons` VALUES (1512, '宋光宗', ' 宋光宗赵惇（1147 - 1200 年），南宋第三位皇帝。即位后限制台谏对皇权约束，开启相权与台谏结党先例，后期朝政混乱。');
INSERT INTO `persons` VALUES (1513, '宋宁宗', ' 宋宁宗赵扩（1168 - 1224 年），南宋第四位皇帝。统治前期韩侂胄把持朝政，后期受史弥远与杨皇后控制，对宋金战争摇摆不定，总体为政忠厚。');
INSERT INTO `persons` VALUES (1514, '宋理宗', ' 宋理宗赵昀（1205 - 1264 年），南宋第五位皇帝。前期受史弥远挟制，亲政后推行 “端平更化”，联蒙灭金；晚年荒淫，朝政落入奸相之手，国势衰微。');
INSERT INTO `persons` VALUES (1515, '宋度宗', ' 宋度宗赵禥（1240 - 1274 年），南宋第六位皇帝。沉迷酒色，重用贾似道，致使朝政腐败，面对蒙军进攻无所作为，南宋统治岌岌可危。');
INSERT INTO `persons` VALUES (1516, '宋恭帝', ' 宋恭帝赵?（1271 - 1323 年），南宋第七位皇帝。在位时元军攻宋，被迫退位降元，后被遣送吐蕃出家，因文字狱被赐死。');
INSERT INTO `persons` VALUES (1517, '宋端宗', ' 宋端宗赵昰（1269 - 1278 年），南宋第八位皇帝。临安陷落后在福州即位，后在元军追击下流亡，最终在颠沛中病死。');
INSERT INTO `persons` VALUES (1518, '赵昺', '赵昺（1272 - 1279 年），南宋末代皇帝。崖山海战后，左丞相陆秀夫背着他跳海而亡，南宋灭亡。');
INSERT INTO `persons` VALUES (1601, '耶律阿保机', '耶律阿保机（872 年－926 年 9 月 6 日），契丹迭剌部人，辽朝创建者，916 年 3 月 17 日－926 年 9 月 6 日在位。初任挞马狘沙里，后统一契丹诸部，建立契丹国，称大圣大明天皇帝，年号神册。并行汉制与草原行国体制，南侵西征，东征渤海国建东丹国，回军途中病逝，谥号升 [昇] 天皇帝，庙号太祖。');
INSERT INTO `persons` VALUES (1602, '耶律德光', '耶律德光（902 年 —947 年），辽太祖次子，辽朝第二代皇帝。早年为天下兵马大元帅，天显元年即位，协助石敬瑭灭后唐得燕云十六州，改官制实行胡汉分治，灭后晋建国号大辽，后因中原汉人反抗罢兵北还，途中病逝，开拓辽朝疆域，确立 “南北兼制\\” 体制。');
INSERT INTO `persons` VALUES (1603, '耶律阮', '辽世宗耶律阮（917 年 1 月 29 日 —951 年 10 月 7 日），辽太祖长孙，辽朝第三位皇帝。太宗死后被拥立为帝，经横渡之约稳固帝位，即位后对中原用兵，扶植北汉，因内部反叛不断，后在祭父时被耶律察割等人所杀，谥号孝和皇帝，庙号世宗。');
INSERT INTO `persons` VALUES (1604, '耶律璟', '辽穆宗耶律璟（931 年 9 月 19 日 —969 年 3 月 12 日），辽太宗长子，辽朝第四位皇帝。诛杀耶律察割后即位，尊号天顺皇帝，虽减免赋税、礼敬臣下，但对近侍残忍，后期酗酒荒政，最终在黑山之变中被弑杀，庙号穆宗，谥号孝安敬正皇帝。');
INSERT INTO `persons` VALUES (1605, '耶律贤', '辽景宗耶律贤（948 年 9 月 1 日 —982 年 10 月 13 日），辽世宗次子，辽朝第五位皇帝。穆宗被杀后即位，尊号 “天赞皇帝\\”，重用汉族官吏，对外援北汉抵宋，与宋有战有和，重视人才、善于纳谏，使辽朝走上中兴之路，谥号孝成康靖皇帝，庙号景宗。');
INSERT INTO `persons` VALUES (1606, '耶律隆绪', '辽圣宗耶律隆绪（972 年 1 月 16 日～1031 年 6 月 25 日），辽景宗长子，辽朝第六位皇帝。即位初期太后萧绰摄政，后亲政。对内改革吏治、开科取士，对外联合党项抗宋，订立 “澶渊之盟\\”，使辽朝达鼎盛，在位四十九年，庙号圣宗，谥号文武大孝宣皇帝。');
INSERT INTO `persons` VALUES (1607, '耶律宗真', '耶律宗真（1016 年～1055 年），辽圣宗长子，辽朝第七位皇帝。即位初期权力被生母掌握，后铲除其势力。在位时政治上无法延续盛世致国内矛盾尖锐，要挟北宋增岁币，亲征西夏，重用汉人，绘有《千角鹿图》，庙号兴宗，谥号神圣孝章皇帝。');
INSERT INTO `persons` VALUES (1608, '耶律洪基', '耶律洪基（1032 年 9 月 14 日 - 1101 年 2 月 12 日），辽兴宗长子，辽朝第八任皇帝。即位后平耶律重元之乱，后听信谗言杀皇后及太子，晚年镇压鞑靼反抗。著有《清宁集》，倡导华夷同风，但因笃信佛教致国力消耗，辽朝走向衰落。');
INSERT INTO `persons` VALUES (1609, '耶律延禧', '耶律延禧（1075 年 6 月 5 日 —1128 年），辽道宗之孙，辽朝第九位也是末代皇帝，尊号天祚皇帝。乾统元年到保大五年在位，辽朝在其统治期间走向灭亡 。');
INSERT INTO `persons` VALUES (1701, '李元昊', '李元昊（1032 年 - 1048 年在位），党项族人，西夏开国皇帝。继夏国公位后弃李姓，自称嵬名氏，1038 年称帝建国号大夏，定都兴庆。他创造西夏文、颁布秃发令，通过战争奠定宋、辽、夏三分天下格局，后期沉湎酒色、好大喜功，因宫廷政变被杀。');
INSERT INTO `persons` VALUES (1702, '李谅祚', '李谅祚（1048 年 - 1068 年在位），李元昊之子，生母没藏氏。在位期间收降吐蕃首领，巩固西夏南疆，亲附辽朝并进贡，增强了西夏影响力。');
INSERT INTO `persons` VALUES (1703, '李秉常', '李秉常（1068 年 - 1086 年在位），李谅祚之子，7 岁继位由梁太后执政。此时宋朝因王安石变法国力增强，熙河之战中宋朝占领熙河路，威胁西夏右厢地区。');
INSERT INTO `persons` VALUES (1704, '李乾顺', '李乾顺（1086 年 - 1139 年在位），李秉常长子，杰出的西夏君主、政治家。亲政后采取联辽抗宋，后又联金抗宋策略，维护并拓展了西夏统治。');
INSERT INTO `persons` VALUES (1705, '李仁孝', '李仁孝（1139 年 - 1193 年在位），李乾顺之子。在位期间西夏政治、经济、文化全面发展，是西夏统治繁荣且时间较长的阶段。');
INSERT INTO `persons` VALUES (1706, '李纯佑', '李纯佑（1193 年 - 1206 年在位），李仁孝长子，在位时维持西夏稳定，后被李安全篡位，3 个月后暴毙。');
INSERT INTO `persons` VALUES (1707, '李安全', '李安全（1206 年 - 1211 年在位），李乾顺之孙，1206 年弑君篡位。改变西夏依附金的政策，转而依附蒙古。');
INSERT INTO `persons` VALUES (1708, '李遵顼', '李遵顼（1211 年 - 1223 年在位），李乾顺之孙，1203 年西夏状元，中国历史上唯一状元皇帝。在位坚持附蒙伐金，后受铁木真逼迫传位给儿子。');
INSERT INTO `persons` VALUES (1709, '李德旺', '李德旺（1223 年 - 1226 年在位），李遵顼之子。在位期间联金抗蒙，却无法扭转西夏危局，最终忧悸病亡。');
INSERT INTO `persons` VALUES (1710, '李睍', '李睍（1226 年 - 1227 年在位），西夏末代皇帝。继位后无力抵御蒙古围攻，遇地震后献城投降，最终被处死，西夏灭亡。');
INSERT INTO `persons` VALUES (1801, '金太祖', ' 完颜阿骨打（1068 - 1123 年），金朝开国皇帝。统一女真部落，率部反辽建国，创建猛安谋克组织，奠定金朝基础，堪称杰出军事统帅。');
INSERT INTO `persons` VALUES (1802, '金太宗', ' 完颜晟（1075 - 1135 年），金朝第二代皇帝。继位后灭辽亡北宋，向西夏割地议和。政治上建章立制，军事上仿辽、宋旧制，推动金朝发展。');
INSERT INTO `persons` VALUES (1803, '金熙宗', ' 完颜亶（1119 - 1150 年），金朝第三任皇帝。前期实施改革，完善制度，与宋议和。后期因皇后干政、酗酒妄杀，被完颜亮刺杀。');
INSERT INTO `persons` VALUES (1804, '海陵炀王', ' 完颜亮（1122 - 1161 年），金朝第四位皇帝。杀熙宗自立，迁都燕京，推进封建化改革。后南征南宋失败，死于兵变。工诗词，有文才。');
INSERT INTO `persons` VALUES (1805, '金世宗', ' 完颜雍（1123 - 1189 年），金朝第五位皇帝。在位时平息内乱，与宋和议，出现 “大定之治”。尊崇儒学，保持女真旧俗，被称为 “小尧舜”。');
INSERT INTO `persons` VALUES (1806, '金章宗', ' 完颜璟（1168 - 1208 年），金朝第六位皇帝。征服北方各族，击退南宋北伐，完成女真封建化。在位后期矛盾激化，金朝由盛转弱。');
INSERT INTO `persons` VALUES (1807, '卫绍王', ' 完颜永济（？ - 1213 年），金朝第七位皇帝。在位时蒙古军南下，金军屡败，后被叛变的纥石烈执中派人杀死。');
INSERT INTO `persons` VALUES (1808, '金宣宗', ' 完颜珣（1163 - 1224 年），金朝第八位皇帝。权臣拥立为帝，南迁汴京致蒙金战争再起，对外举措失误，使金朝内外交困。');
INSERT INTO `persons` VALUES (1809, '金哀宗', ' 完颜守绪（1198 - 1234 年），金朝第九位皇帝。在位十年，尝试改革与抗蒙，后期决策失误，最终自缢，金朝灭亡。');
INSERT INTO `persons` VALUES (1810, '金末帝', ' 完颜承麟（1202 - 1234 年），金朝末代皇帝。金哀宗传位予他，即位大典未毕便遇宋蒙联军攻城，死于乱军，在位时间不足一时辰，为中国在位最短皇帝。');
INSERT INTO `persons` VALUES (1901, '孛儿只斤?忽必烈', '孛儿只斤?忽必烈（1215 年 9 月 23 日－1294 年 2 月 18 日），元朝开国皇帝，成吉思汗之孙。他攻灭南宋实现大一统，推行汉法，建立行省制度，重视农桑文教，但对外征战多有失利，奠定元朝统治基础。');
INSERT INTO `persons` VALUES (1902, '孛儿只斤?铁穆耳', '孛儿只斤?铁穆耳（1265 年 10 月 - 1307 年 2 月），元朝第二位皇帝，元世祖忽必烈之孙。在位时轻徭薄赋，稳定边疆，维持守成局面，但因赏赐无度致国库空虚，后期朝政渐趋腐败。');
INSERT INTO `persons` VALUES (1903, '孛儿只斤?海山', '孛儿只斤?海山（1281 年 —1311 年），元朝第三位皇帝。他在位推行改革，设立尚书省、发行新钞，尊崇佛教并加封孔子，虽改革未竟全功，但对元朝政治经济影响深远。');
INSERT INTO `persons` VALUES (1904, '孛儿只斤?爱育黎拔力八达', '孛儿只斤?爱育黎拔力八达（1285 年 4 月 9 日 - 1320 年 3 月 1 日），元朝第四位皇帝。其以儒治国，恢复科举，整顿朝政，推动元朝短暂中兴，但违背帝位继承约定引发矛盾。');
INSERT INTO `persons` VALUES (1905, '孛儿只斤?硕德八剌', '孛儿只斤?硕德八剌（1303 年 2 月 22 日 —1323 年 9 月 4 日），元朝第五位皇帝。他推行 “至治新政\\” 以革新图治，却因触动守旧势力，在 “南坡之变\\” 中遇刺身亡。');
INSERT INTO `persons` VALUES (1906, '孛儿只斤?也孙铁木儿', '孛儿只斤?也孙铁木儿（1293 年 —1328 年），元朝第六位皇帝。即位后惩处弑君者，推行汉法，崇佛建寺，维持统治稳定，病卒后未获谥号庙号。');
INSERT INTO `persons` VALUES (1907, '孛儿只斤?阿速吉八', '孛儿只斤?阿速吉八（1320 年 —1328 年），元朝第七位皇帝。泰定帝死后在上都称帝，与大都争位失败，下落不明，无谥号庙号。');
INSERT INTO `persons` VALUES (1908, '孛儿只斤?图帖睦尔', '孛儿只斤?图帖睦尔（1304 年 2 月 16 日 —1332 年 9 月 2 日），两度在位的元朝第八位皇帝。他创建奎章阁，编修典籍，推动文化发展，但受权臣操控，统治内部矛盾尖锐。');
INSERT INTO `persons` VALUES (1909, '孛儿只斤?和世?', '孛儿只斤?和世?（1300 年 12 月 22 日 —1329 年 8 月 30 日），元朝第九位皇帝。被弟弟图帖睦尔迎立后遭毒杀，在位短暂，加剧皇室权力斗争。');
INSERT INTO `persons` VALUES (1910, '孛儿只斤?懿璘质班', '孛儿只斤?懿璘质班（1326 年 5 月 1 日 —1332 年 12 月 14 日），元朝第十位皇帝。7 岁即位，在位 43 天病逝，因年幼早逝未展抱负，谥号冲圣嗣孝皇帝，庙号宁宗。');
INSERT INTO `persons` VALUES (1911, '孛儿只斤?妥懽帖睦尔', '孛儿只斤?妥懽帖睦尔（1320 年 5 月 25 日 —1370 年 5 月 23 日），元朝末代皇帝。前期推行改革，后期统治腐败，致使农民起义爆发，最终元朝灭亡，他北逃后病逝。');
INSERT INTO `persons` VALUES (2001, '朱元璋', '朱元璋（1328 年 10 月 21 日 —1398 年 6 月 24 日），明朝开国皇帝，1368 年 —1398 年在位，年号 “洪武\\”。曾参加红巾军反元，陆续消灭割据势力，推翻元朝统治，统一全国。在位强化中央集权，严惩贪腐，推行卫所制，兴屯田，抓教育，开创 “洪武之治\\”，病逝后传位朱允炆。');
INSERT INTO `persons` VALUES (2002, '朱允炆', '朱允炆（1377 年 12 月 5 日 —？），明朝第二位皇帝，1398 年 —1402 年在位，年号 “建文\\”。朱元璋之孙，即位后实行 “建文新政\\”，削藩加强集权，引发 “靖难之役\\”，后在战乱中下落不明。');
INSERT INTO `persons` VALUES (2003, '朱棣', '朱棣（1360 年 5 月 2 日 —1424 年 8 月 12 日），明朝第三位皇帝，1402 年 —1424 年在位，年号 “永乐\\”。朱元璋第四子，通过 “靖难之役\\” 登基。在位继续削藩，设内阁、东厂，迁都北京，五征蒙古，派郑和下西洋，修《永乐大典》，但耗费国力，传位朱高炽。');
INSERT INTO `persons` VALUES (2004, '朱高炽', '朱高炽（1378 年 8 月 16 日 —1425 年 5 月 29 日），明朝第四位皇帝，年号 “洪熙\\”。朱棣长子，靖难时守北平，多次监国。在位为政开明，与民休息，赦免旧臣，平反冤狱，调整机构，为 “仁宣之治\\” 奠基，著有诗文，传位朱瞻基。');
INSERT INTO `persons` VALUES (2005, '朱瞻基', '朱瞻基（1398 年 / 1399 年 3 月 16 日 —1435 年 1 月 31 日），明朝第五位皇帝，1425 年 —1435 年在位，年号 “宣德\\”。朱高炽之子，早年受朱棣宠爱。在位重视吏治财政，平定汉王叛乱，与父统治合称 “仁宣之治\\”，曾第七次派郑和下西洋，病逝前实行了一些稳定统治的措施，留有画作。');
INSERT INTO `persons` VALUES (2006, '朱祁镇', '朱祁镇（1427 年 11 月 29 日 —1464 年 2 月 23 日），明朝第六位皇帝，1435 年 —1449 年、1457 年 —1464 年在位，年号 “正统\\”“天顺\\”。朱瞻基长子，九岁即位，前期由三杨辅政，后王振弄权，“土木之变\\” 被掳，放回后被软禁，“夺门之变\\” 复辟，遗诏废嫔妃殉葬制。');
INSERT INTO `persons` VALUES (2007, '朱祁钰', '朱祁钰（1428 年 9 月 11 日～1457 年 3 月 14 日），明朝第七位皇帝，1449 年 —1457 年在位，年号 “景泰\\”。朱瞻基次子，“土木堡之变\\” 后即位，组织北京保卫战，稳定时局，发展经济，后被明英宗复位，未葬入帝陵，后获皇帝名号。');
INSERT INTO `persons` VALUES (2008, '朱见深', '朱见深（1447 年 12 月 9 日 —1487 年 9 月 9 日），明朝第八位皇帝，1464 年 —1487 年在位，年号 “成化\\”。朱祁镇长子，即位初平反于谦冤狱，恢复景帝帝号。前期能臣汇集，后期怠政，宠信万贵妃，崇信道术，驾崩前有裁汰之举，留有文化作品。');
INSERT INTO `persons` VALUES (2009, '朱祐樘', '朱祐樘（1470 年 7 月 30 日－1505 年 6 月 8 日），明朝第九位皇帝，1487 年 —1505 年在位，年号 “弘治\\”。朱见深第三子，在位宽厚仁慈，躬行节俭，勤于政事，起用贤能，减省费用，兴修水利，编《大明会典》，史称 “弘治中兴\\”，虽有危机但能改过。');
INSERT INTO `persons` VALUES (2010, '朱厚照', '朱厚照（1491 年 10 月 26 日 —1521 年 4 月 20 日），明朝第十位皇帝，1505 年 —1521 年在位，年号 “正德\\”。朱祐樘长子，设立豹房，宠信宦官，多次出巡，曾亲自领兵应州之战，通晓多语言，平息宗室叛乱，后落水致病驾崩。');
INSERT INTO `persons` VALUES (2011, '朱厚熜', '朱厚熜（1507 年 9 月 16 日 —1567 年 1 月 23 日），明朝第十一位皇帝，1521 年 —1567 年在位，年号 “嘉靖\\”。兴献王之子，即位后 “大礼议\\”，前期改革称 “嘉靖新政\\”，后期迷信方士，严嵩专权，“南倭北虏\\” 困扰，驾崩于乾清宫。');
INSERT INTO `persons` VALUES (2012, '朱载坖', '朱载坖（1537 年 3 月 4 日 —1572 年 7 月 5 日），明朝第十二位皇帝，1567 年 —1572 年在位，年号 “隆庆\\”。朱厚熜第三子，在位委任阁臣，兴利除弊，重用帅才加强边防，实现隆庆开关和俺答封贡，因纵情声色身体渐差。');
INSERT INTO `persons` VALUES (2013, '朱翊钧', '朱翊钧（1563 年 9 月 4 日 —1620 年 8 月 18 日），明朝第十三位皇帝，1572 年 —1620 年在位，年号 “万历\\”，在位最长。朱载坖第三子，前期靠张居正改革，亲政后开创 “万历中兴\\”，后倦于朝政，后金崛起，明军萨尔浒惨败，对明影响巨大。');
INSERT INTO `persons` VALUES (2014, '朱常洛', '朱常洛（1582 年 8 月 28 日 —1620 年 9 月 26 日），明朝第十四位皇帝，1620 年在位，年号 “泰昌\\”。朱翊钧之子，经历 “国本之争\\”“梃击案\\”，即位后改革，却 “惑于女宠\\”，后因 “红丸案\\” 驾崩，为后续宫廷纷争埋下伏笔。');
INSERT INTO `persons` VALUES (2015, '朱由校', '朱由校（1605 年 12 月 23 日 —1627 年 9 月 30 日），明朝第十五位皇帝，1620 年 —1627 年在位，年号 “天启\\”。朱常洛长子，在位初用东林党，后魏忠贤与客氏专权，内忧外患，国内矛盾激化，辽东局势严峻，后因溺水致病驾崩。');
INSERT INTO `persons` VALUES (2016, '朱由检', '朱由检（1611 年 2 月 6 日 —1644 年 4 月 25 日），明朝第十六位皇帝，1627 年 —1644 年在位，年号 “崇祯\\”。朱常洛第五子，即位后试图挽救明朝，铲除魏忠贤势力，但内忧外患严重，最终在李自成攻破北京后自缢，明朝灭亡。');
INSERT INTO `persons` VALUES (2101, '爱新觉罗?努尔哈赤', '爱新觉罗?努尔哈赤（1559 年 —1626 年），女真族政治家、军事家，后金政权创建者，清王朝奠基人。以遗甲 13 副起兵，统一女真各部，创制满文，设八旗。1616 年建后金，年号天命，后伐明，经萨尔浒之战等，完成女真统一，迁都辽阳、沈阳，于宁远之战败后疽发而死，庙号太祖，葬于沈阳福陵。');
INSERT INTO `persons` VALUES (2102, '爱新觉罗?皇太极', '爱新觉罗?皇太极（1592 年 11 月 28 日 —1643 年 9 月 21 日），后金第二位大汗，后称帝改国号大清。努尔哈赤第八子，即位后改革，加强集权，征服朝鲜、漠南蒙古，重用汉将，削弱明朝。1636 年称帝，后赢得松锦大战，为清朝入主中原奠基，庙号太宗，葬于沈阳昭陵。');
INSERT INTO `persons` VALUES (2103, '爱新觉罗?福临', '爱新觉罗?福临（1638 年 3 月 15 日 —1661 年 2 月 5 日），清朝第三位皇帝，定都北京首位皇帝。六岁登基，由多尔衮摄政，1644 年清军入关迁都北京。亲政后加强皇权，缓和民族矛盾，整顿吏治，推行屯田、垦荒，平抗清力量，庙号世祖，葬于清东陵之孝陵。');
INSERT INTO `persons` VALUES (2104, '爱新觉罗?玄烨', '爱新觉罗?玄烨（1654 年 5 月 4 日 —1722 年 12 月 20 日），清朝第四位皇帝，在位 61 年。8 岁登基，14 岁亲政，平三藩、收台湾、抗沙俄、征噶尔丹，加强集权，发展经济，开创康乾盛世，庙号圣祖，葬于景陵。');
INSERT INTO `persons` VALUES (2105, '爱新觉罗?胤禛', '爱新觉罗?胤禛（1678 年 12 月 13 日 —1735 年 10 月 8 日），清朝第五位皇帝。康熙第四子，即位后改革，改土归流，摊丁入亩，整顿财政，设军机处，改善立储，勤于政事，对康乾盛世连续关键，庙号世宗，葬清西陵之泰陵。');
INSERT INTO `persons` VALUES (2106, '爱新觉罗?弘历', '爱新觉罗?弘历（1711 年 9 月 25 日 —1799 年 2 月 7 日），清朝第六位皇帝，实际掌权最久且最长寿。在康雍基础上统一多民族国家，发展经济文化，完善对西藏统治，扩版图，开博学鸿词科，修《四库全书》，后期宠和珅，中国与西方差距拉大，庙号高宗，葬于裕陵。');
INSERT INTO `persons` VALUES (2107, '爱新觉罗?颙琰', '爱新觉罗?颙琰（1760 年 11 月 13 日 —1820 年 9 月 2 日），清朝第七位皇帝。乾隆第十五子，亲政后诛和珅，平白莲教、天理教起义，政绩不显著，为守成君主，在位时清朝由盛转衰，鸦片输入严重，庙号仁宗，葬清西陵之昌陵。');
INSERT INTO `persons` VALUES (2108, '爱新觉罗?旻宁', '爱新觉罗?旻宁（1782 年 9 月 16 日 —1850 年 2 月 25 日），清朝第八位皇帝。嘉庆第二子，即位后改革漕运盐政，禁鸦片，鸦片战争战败签《南京条约》，虽勤政但鲜有作为，庙号宣宗，葬清西陵之慕陵。');
INSERT INTO `persons` VALUES (2109, '爱新觉罗?奕詝', '爱新觉罗?奕詝（1831 年 7 月 17 日 —1861 年 8 月 22 日），清朝及中国最后有实际统治权皇帝。旻宁第四子，即位后改革，用曾国藩等镇压起义，罢斥投降派。第二次鸦片战争时逃热河，病逝于承德，庙号文宗，葬清东陵之定陵。');
INSERT INTO `persons` VALUES (2110, '爱新觉罗?载淳', '爱新觉罗?载淳（1856 年 4 月 27 日 —1875 年 1 月 12 日），清朝第十位皇帝。咸丰长子，6 岁即位，两宫太后垂帘听政，平太平天国等起义，行 “同治新政\\”，亲政后难脱慈禧干预，19 岁染天花去世，庙号穆宗，葬于惠陵。');
INSERT INTO `persons` VALUES (2111, '爱新觉罗?载湉', '爱新觉罗?载湉（1871 年 8 月 14 日 —1908 年 11 月 14 日），清朝第十一位皇帝。4 岁即位，两宫垂帘，亲政后名义掌权。甲午战败签《马关条约》，支持戊戌变法被囚，八国联军时出逃，后形同傀儡，先慈禧去世，庙号德宗，葬于清西陵之崇陵。');
INSERT INTO `persons` VALUES (2112, '爱新觉罗?溥仪', '爱新觉罗?溥仪（1906 年 2 月 7 日 —1967 年 10 月 17 日），清朝末代皇帝。1908 年即位，1912 年退位，后曾复辟，在伪满洲国为傀儡皇帝，战后被改造，成为普通公民。');
