INSERT INTO `powers` VALUES (1, '夏', '夏朝（约公元前2070年—约公元前1600年），是中国史书中记载的第一个奴隶制朝代。');
INSERT INTO `powers` VALUES (101, '商', '商朝（约公元前1600年—公元前1046年 ），是中国历史上的第二个朝代，也称殷商，是中国第一个有直接的同时期的文字记载的王朝。');
INSERT INTO `powers` VALUES (201, '西周', '西周（前1046～前771年），中国历史朝代。从周武王灭商到幽王亡国， 共传12王11代。');
INSERT INTO `powers` VALUES (301, '东周', '东周（公元前770年－公元前256年），中国历史上的朝代。西周覆灭后，诸侯拥立原先被废的太子姬宜臼为王，史称周平王，东迁洛邑（今洛阳），史称东周。');
INSERT INTO `powers` VALUES (302, '齐国', '齐国（公元前1046年—前221年）是中国历史上从西周到春秋战国时期的一个诸侯国，被周天子封为侯爵，分为姜齐和田齐两个时期，疆域位于现今山东省大部，河北省南部。');
INSERT INTO `powers` VALUES (303, '晋国', '晋国（公元前1033年—前376年），周朝周武王之子的姬姓诸侯国，周初被周天子封为侯爵，姬姓晋氏，首任国君唐叔虞为周武王姬发之子，周成王姬诵之弟。国号初为唐，唐叔虞之子燮即位后改为晋。');
INSERT INTO `powers` VALUES (304, '秦国', '秦国（公元前770年—前207年），是周朝时在中国西北地区建立的诸侯国。');
INSERT INTO `powers` VALUES (305, '楚国', '楚国（？～前223年），又称荆、荆楚，是先秦时期位于长江流域的诸侯国，国君为芈姓（金文中为嬭姓）、熊氏（金文中为酓氏）。周成王时期（一说即前1042年～1021年），封楚人首领熊绎为子爵，建立楚国。');
INSERT INTO `powers` VALUES (306, '魏国', '魏国（公元前403年—公元前225年），周朝的周王族诸侯国之一，也是战国七雄之一。姬姓，魏氏，始祖为毕万（毕公高之裔孙）。');
INSERT INTO `powers` VALUES (307, '韩国', '韩国（公元前403-公元前230），周朝的周王族诸侯国，是战国七雄之一，与魏国、赵国合称三晋，国君为姬姓韩氏，是晋国大夫韩武子的后代。');
INSERT INTO `powers` VALUES (308, '赵国', '赵国（公元前403年—公元前222年），中国春秋战国时期诸侯国，战国七雄之一。是战国后期东方六国最强大的国家，与秦国展开了数十年的争霸。');
INSERT INTO `powers` VALUES (309, '燕国', '燕国（公元前1044年—前222年），本称“匽”、“郾”，周朝的诸侯国、战国七雄之一，是周朝的支族，国祚八百二十二年。');
INSERT INTO `powers` VALUES (401, '秦', '秦朝（前221年—前207年），是中国历史上第一个统一的封建王朝，秦朝结束了自战国以来诸侯分裂割据的局面，成为中国历史上第一个中央集权制国家。');
INSERT INTO `powers` VALUES (501, '西汉', '西汉（公元前202年 —8年 ），是中国历史上继秦朝之后的中央王朝，汉高祖刘邦所建，传十一代十二帝 ，历时210年 ，史称为“前汉”，亦有“西京”之称。');
INSERT INTO `powers` VALUES (502, '新朝', '新朝（公元9年1月15日–23年10月6日），是继西汉之后由西汉外戚王莽建立的朝代。');
INSERT INTO `powers` VALUES (503, '更始', '更始，公元23年2月，绿林军领导者拥立刘玄为帝，恢复汉朝国号，建立的更始政权，自称玄汉王朝。消灭王莽政权后统治天下两年。公元25年，赤眉军攻入都城长安，投降赤眉，更始政权告终。');
INSERT INTO `powers` VALUES (504, '东汉', '东汉（25年—220年），中国历史上继西汉之后的大一统中原王朝，传八世共十四帝，享国一百九十五年，与西汉统称两汉。');
INSERT INTO `powers` VALUES (601, '蜀汉', '蜀汉（221年—263年），三国时期的割据政权之一。公元221年，刘备在成都称帝，国号汉，后世称“季汉”、“蜀汉”、“西蜀”、“刘蜀”等。263年为魏国所灭，共历二世二帝，国祚四十三年。');
INSERT INTO `powers` VALUES (602, '东吴', '孙吴（222年－280年），三国时期割据政权之一，是孙权在中国东南部建立的政权，国号为“吴”，史学界称为孙吴。由于与曹魏、蜀汉呈鼎立之势，所统治地区又在三国东部，故也称东吴。');
INSERT INTO `powers` VALUES (603, '曹魏', '魏国（220年—266年）是三国时期割据政权之一，后世史家多称曹魏，由于之后的北魏被称作“后魏”，故曹魏也称为“前魏”或者“先魏”，是三国之中最强大的国家。');
INSERT INTO `powers` VALUES (701, '西晋', '西晋（265年 —316年），是中国历史上短暂的大一统王朝。传三世四帝 ，共51年。为了区别于五代时的后晋，史称西晋，又称为司马晋。');
INSERT INTO `powers` VALUES (801, '东晋', '东晋（317年—420年），是西晋皇族南迁后建立的王朝，是晋朝的继续。');
INSERT INTO `powers` VALUES (901, '前凉', '前凉（318年～376年），东晋十六国时期政权之一，都城姑臧，割据西北的地方政权，前凉传五世八主，享国五十九年。');
INSERT INTO `powers` VALUES (902, '成汉', '成汉（304年～347年）是十六国政权之一。');
INSERT INTO `powers` VALUES (903, '前赵', '前赵（304年～329年），亦称汉赵，十六国时期列国之一，是西晋晚期由匈奴贵族刘渊建立的割据政权。');
INSERT INTO `powers` VALUES (904, '后赵', '后赵（319年～351年）是十六国时期羯族首领石勒建立的政权，盛时疆域有今河北、山西、陕西、河南、山东及江苏、安徽、甘肃、辽宁的一部分。共历七帝，享国三十三年。');
INSERT INTO `powers` VALUES (905, '前燕', '前燕（337年～370年），十六国时期鲜卑族贵族首领慕容皝所建立的国家，国号为“燕”，全盛时期统治地区包括冀州、兖州、青州、并州、豫州、徐州、幽州等部分，历三世两主，共十九年。从慕容皝称王算起是三十四年。');
INSERT INTO `powers` VALUES (906, '前秦', '前秦（351年～394年）是氐族雄主苻健建立的政权，也是十六国中最强大的国家。前秦历五世共六帝（含追封共六世八帝），享国四十四年，从苻洪称王算起是四十六年。');
INSERT INTO `powers` VALUES (907, '后燕', '后燕（384年～407年）是十六国时期鲜卑慕容氏诸燕之一，建立者为前燕文明帝慕容皝第五子慕容垂。后燕历三世四主，国祚共二十四年。后燕初期定都中山，后迁往龙城，全盛时有今河北、辽宁全境及山西、河南、山东、内蒙古部分地区。');
INSERT INTO `powers` VALUES (908, '后秦', '后秦（384年～417年）是十六国时期羌族姚苌建立的政权。共历三世三帝，享国三十四年。');
INSERT INTO `powers` VALUES (909, '西秦', '西秦 (385年～400年、409～431年)，五胡十六国政权之一。陇西鲜卑族首领乞伏国仁所建。');
INSERT INTO `powers` VALUES (910, '后凉', '后凉（386年—403年），十六国之一，都城姑臧，由吕光建立，历4王，17年。以地处凉州为国号。');
INSERT INTO `powers` VALUES (911, '南凉', '南凉（397年—414年），是十六国政权之一，国号凉，共历二世三主，共十八年，十六国政权之一，为拓跋鲜卑政权。');
INSERT INTO `powers` VALUES (912, '西凉', '西凉（400年—421年），李广后裔李暠于公元400年建立的王朝，在敦煌自称“凉公”。');
INSERT INTO `powers` VALUES (913, '北凉', '北凉（397年—460年），十六国之一，都城姑臧。开创者是段业。');
INSERT INTO `powers` VALUES (914, '南燕', '南燕（398年～410年），十六国时期慕容氏诸燕之一，由慕容德所建。统治范围包括今山东及江苏的一部分，国号为燕，定都广固。');
INSERT INTO `powers` VALUES (915, '北燕', '北燕（407年～436年）是十六国时期高云、冯跋建立的政权。历二主，共28年。');
INSERT INTO `powers` VALUES (916, '大夏', '大夏（407年~431年）是南匈奴屠各种铁弗部族人赫连勃勃建立的政权，史称“胡夏”。定都统万城，十六国时期最后出现的一个政权。');
INSERT INTO `powers` VALUES (1001, '北魏', '北魏（386年—534年），南北朝时期北朝的第一王朝。也称拓跋魏 元魏，鲜卑族拓跋氏所建，传12帝（列入正史帝纪者）。');
INSERT INTO `powers` VALUES (1002, '西魏', '西魏（535年―556年），南北朝时期由北魏分裂出来的地方王朝。元宝炬在以宇文泰为首的诸臣支持下称帝，国号魏，后世称之为西魏。与高欢所掌控的东魏和南朝梁对立，建都长安（今陕西西安）。557年被北周取代，经历两代三帝，历时二十二年。');
INSERT INTO `powers` VALUES (1003, '东魏', '东魏（534年-550年），南北朝时期属北朝割据政权之一，从北魏分裂出来的政权。历时十七年，共一帝。东魏建都邺（今河北省邯郸市临漳县），以晋阳（今山西省太原市）为别都，高欢坐镇晋阳遥控朝廷。');
INSERT INTO `powers` VALUES (1004, '北齐', '北齐（550年～577年），南北朝时期的北朝政权之一，由东魏权臣高欢次子高洋所建。历经六帝，享国二十八年。因皇室姓氏为高氏，故又称高齐。');
INSERT INTO `powers` VALUES (1005, '北周', '北周（557年—581年）是中国历史上南北朝的北朝之一，由西魏权臣宇文泰奠定国基，由宇文觉在宇文护的拥立下正式建立。又称后周、宇文周。历五帝，共二十四年。');
INSERT INTO `powers` VALUES (1101, '南宋', '南朝刘宋（420—479），是中国南北朝时期南朝的第一个朝代，是南朝中存在时间最久、疆域最大的朝代。共传四世，历经十帝，享国59年。因国君姓刘，为与赵匡胤建立的赵宋相区别，又称为刘宋；按五德终始之说，其为水德，又称水宋。');
INSERT INTO `powers` VALUES (1102, '南齐', '南齐（479年～502年），是南北朝时期南朝的第二个朝代。为萧道成所建，定都建康（今江苏南京）。');
INSERT INTO `powers` VALUES (1103, '南梁', '南朝梁（502年-557年），是中国南北朝时期的南朝第三个朝代，由雍州刺史萧衍取代南齐称帝，定都建康（今江苏省南京市）。国号梁，以萧衍封地在古梁郡，故定国号为梁。因皇室姓萧，又称萧梁。');
INSERT INTO `powers` VALUES (1104, '南陈', '陈朝（557年－589年），史称南陈、南朝陈，是南北朝时期的南朝最后一个朝代，为陈武帝陈霸先所建立，定都建康（今江苏省南京市）。传五帝，共历三十二年。');
INSERT INTO `powers` VALUES (1201, '隋朝', '隋朝（581年—618年），是中国历史上继南北朝之后的统一王朝，享国38年。');
INSERT INTO `powers` VALUES (1301, '唐朝', '唐朝（618年－907年），是中国历史上继隋朝后的大一统中原王朝，共历二十一帝，享国二百八十九年。');
INSERT INTO `powers` VALUES (1401, ' 后梁 ', ' 后梁（907 年 —923 年），是五代的第一个朝代。唐天祐四年（907 年）四月，梁王朱晃（本名朱温，唐帝赐名朱全忠）受唐哀帝李柷禅让，称帝建国，国号梁，史称后梁，唐朝正式覆灭。后梁先定都开封（今河南开封），后迁都洛阳。');
INSERT INTO `powers` VALUES (1402, ' 后唐 ', ' 后唐（923 年 —936 年）是五代十国时期由沙陀族建立的封建王朝，定都洛阳（今河南洛阳），传二世四帝，历时一十四年。');
INSERT INTO `powers` VALUES (1403, ' 后晋 ', ' 后晋（936 年 —947 年），是五代第三个政权，从后唐清泰三年（936 年，契丹天显十一年）十一月石敬瑭受契丹册封为帝，到契丹于后晋开运四年（947 年，契丹会同十年）灭后晋，一共经历了两帝，共 11 年，初定都洛阳，后迁都开封。');
INSERT INTO `powers` VALUES (1404, ' 后汉 ', ' 后汉（947 年 —950 年），五代十国时期五代的第四个朝代，由刘暠（本名刘知远）建立，都城在东京开封府（今河南省开封市）。共历二帝，享国三年。');
INSERT INTO `powers` VALUES (1405, ' 后周 ', ' 后周（951 年－960 年），中国五代时期中原最后一个王朝，定都东京开封府，共历三帝，享国十年。');
INSERT INTO `powers` VALUES (1406, ' 前蜀 ', ' 前蜀（907 年 —925 年），五代十国之一，后梁开平元年（907 年）由王建所建的割据政权，定都于成都（今四川省成都市）。前蜀历二主，共 18 年。');
INSERT INTO `powers` VALUES (1407, ' 后蜀 ', ' 后蜀（934 年 —966 年），又称孟蜀，是五代十国之一，孟知祥所建立的政权，定都成都。共二帝，历 32 年。');
INSERT INTO `powers` VALUES (1408, ' 吴国 ', ' 吴国（902 年 —937 年），是五代十国时期十国的政权之一。为杨行密所建，建都江都府（今江苏扬州）。历四主，享国三十五年。若从 892 年杨行密受封淮南节度使计，为 46 年。');
INSERT INTO `powers` VALUES (1409, ' 南唐 ', ' 南唐（937 年 —975 年），是五代十国时期李昪在江南地区建立的王朝，定都江宁（今江苏省南京市），传三世历一帝二主，享国三十八年，是十国中版图最大的政权。');
INSERT INTO `powers` VALUES (1410, ' 吴越 ', ' 吴越（907 年～978 年），又称义忠国，是五代十国时期的十国之一，统治者为临安钱氏。由钱镠在后梁开平元年（907 年）所建，定都杭州。');
INSERT INTO `powers` VALUES (1411, ' 闽国 ', ' 闽国（909 年 —945 年），五代十国之一，先后定都于长乐府（今福建福州）、建州（今福建建瓯）。统治区域与今福建省大致相当。历七主，共五十三年。');
INSERT INTO `powers` VALUES (1412, ' 楚国 ', ' 楚国（907 年 —951 年），五代十国时期南方十国之一，历史上唯一以湖南为中心建立的政权，史称马楚，以潭州（今长沙）为首都。');
INSERT INTO `powers` VALUES (1413, ' 南汉 ', ' 南汉（917 年 —971 年），是五代十国之一。统治范围包括今广东、广西、海南三省，历四帝，国祚 55 年。 追溯至唐天祐二年刘隐正式担任清海节度使算起，刘氏政权历五主，存在长达 67 年。是岭南历史上继南越后建立的第二个地方割据政权。');
INSERT INTO `powers` VALUES (1414, ' 南平 ', ' 南平（924 年 —963 年），又称荆南、北楚，是高季兴所建立的政权，为五代十国时期的十国之一。南平都城为荆州，辖荆、归（今湖北秭归）、峡（今湖北宜昌）三州。历 5 王，共 39 年，从未称帝。');
INSERT INTO `powers` VALUES (1415, ' 北汉 ', ' 北汉（951 年 - 979 年），五代十国之一，也是十国中最后一个政权。都城晋阳（今山西省太原市）。领土为十二州，位置大致在现代的山西省中部和北部。北汉依附契丹族建立的辽朝，979 年，被北宋所灭。历四帝，共 28 年。');
INSERT INTO `powers` VALUES (1501, '宋朝', '宋朝是中国历史上商品经济、文化教育繁荣的时代。这一时期，政治相对开明，农业发展，商业和城市繁荣，社会变化，儒学复兴后形成程朱理学，科技发展迅速，宋词兴盛，书法、绘画艺术也取得很高的成就。');
INSERT INTO `powers` VALUES (1601, '辽朝', '辽朝（916—1125年），是中国历史上由契丹族建立的朝代，又称大契丹，民间或称大蕃。与北宋、西夏并立。共传九帝，经历二百零九年。');
INSERT INTO `powers` VALUES (1701, '西夏', '西夏（1038年—1227年），是中国历史上由党项人在中国西北部建立的朝代，自称“邦泥定国\\”或“大白高国\\”。因其在西北，故称之为西夏。前期和辽、北宋，后期与金朝、南宋并立。历经十帝，共189年。');
INSERT INTO `powers` VALUES (1801, '金朝', '金朝初期采取贵族合议的勃极烈制度，后逐渐由二元政治走向单一汉制。军事上采行军民合一的猛安谋克制度。金朝的陶瓷业与炼铁业兴盛，对外贸易的榷场还掌控西夏的经济命脉。金朝在文化方面也快速汉化，杂剧与戏曲在金朝得到相当的发展，金代院本为后来元曲的杂剧打下了基础。');
INSERT INTO `powers` VALUES (1901, '元朝', '元朝（1271—1368年），是中国历史上的朝代。铁木真于1206年建国 ，1271年忽必烈定国号为大元 ，1279年灭南宋。是首次由少数民族建立的大一统王朝。自1206年铁木真建国始共163年，传15帝；自忽必烈改国号为大元起共98年，传11帝 ；自灭南宋起，统一时间共89年。');
INSERT INTO `powers` VALUES (2001, '明朝', '明朝（1368年―1644年），中国历史上的朝代，由明太祖朱元璋所建。初期建都南京，明成祖时期迁都北京。传十六帝，共计276年。');
INSERT INTO `powers` VALUES (2101, '清朝', '清朝（1616年或1644年—1911年），是中国历史上最后一个封建王朝，共传十二帝，初称后金。');
